// ══════════════════════════════════════════════════════════════
// HELPERS
// ══════════════════════════════════════════════════════════════
function fmtB(v){
  if(v>=1000) return `$${(v/1000).toFixed(1)}B`;
  return `$${v}M`;
}
function relTime(d){
  const diff=Date.now()-d.getTime();
  if(diff<3600000) return `${Math.floor(diff/60000)}m ago`;
  if(diff<86400000) return `${Math.floor(diff/3600000)}h ago`;
  return `${Math.floor(diff/86400000)}d ago`;
}
function riskScore(p){
  return Math.round(p.budgetRisk*0.35 + p.politicalRisk*0.25 + p.deliveryRisk*0.20 + p.planningRisk*0.12 + p.marketRisk*0.08);
}
function probColor(prob){
  if(prob>=70) return "#10D97A";
  if(prob>=40) return "#FFB020";
  return "#FF4455";
}

// ══════════════════════════════════════════════════════════════
// MAP
// ══════════════════════════════════════════════════════════════
function initMap(){
  map = L.map("map", {
    center: [-33.87, 151.05],
    zoom: 11,
    zoomControl: true,
    attributionControl: true,
    preferCanvas: false,
  });

  // Light basemap (CartoDB Voyager without labels) + labels-on-top layer.
  // This gives clean OSM-style geography with city/road context but lets
  // political fills sit underneath while suburb labels stay visible above.
  const baseTiles = L.tileLayer("https://{s}.basemaps.cartocdn.com/rastertiles/voyager_nolabels/{z}/{x}/{y}{r}.png",{
    attribution:'&copy; <a href="https://carto.com/">CARTO</a> &copy; OpenStreetMap',
    subdomains:'abcd',
    maxZoom: 19,
    crossOrigin: true,
  });

  // Labels overlay — drawn on top of political fills so place names stay readable
  const labelTiles = L.tileLayer("https://{s}.basemaps.cartocdn.com/rastertiles/voyager_only_labels/{z}/{x}/{y}{r}.png",{
    subdomains:'abcd',
    maxZoom: 19,
    pane: "shadowPane",  // standard top pane
  });

  let fallbackLoaded = false;
  baseTiles.on("tileerror", () => {
    if(fallbackLoaded) return;
    fallbackLoaded = true;
    console.warn("Primary tiles failed — loading OSM fallback");
    L.tileLayer("https://tile.openstreetmap.org/{z}/{x}/{y}.png",{
      attribution:'&copy; OpenStreetMap contributors',
      maxZoom: 19,
    }).addTo(map);
  });

  baseTiles.addTo(map);

  // ─── Custom panes for clean polygon stacking (no overlap chaos) ───
  // z-order from bottom to top:
  //   councils (300)  →  state (350)  →  federal (400)  →  marginal (450)
  //   project corridors (500)  →  basemap labels (600)  →  project markers (650)
  map.createPane("councilsPane");   map.getPane("councilsPane").style.zIndex = 300;
  map.createPane("travelPane");     map.getPane("travelPane").style.zIndex = 310;
  map.createPane("statePane");      map.getPane("statePane").style.zIndex = 350;
  map.createPane("federalPane");    map.getPane("federalPane").style.zIndex = 400;
  map.createPane("marginalPane");   map.getPane("marginalPane").style.zIndex = 450;
  map.createPane("corridorsPane");  map.getPane("corridorsPane").style.zIndex = 500;
  map.createPane("labelsPane");     map.getPane("labelsPane").style.zIndex = 600;
  map.createPane("markersPane");    map.getPane("markersPane").style.zIndex = 650;

  // Move basemap labels to labelsPane so they sit above political fills
  labelTiles.options.pane = "labelsPane";
  labelTiles.addTo(map);

  map.on("mousemove", e=>{
    document.getElementById("map-coords").textContent = `${e.latlng.lat.toFixed(4)}°S  ${e.latlng.lng.toFixed(4)}°E`;
  });

  // Fix blank map — invalidate size after mount & on resize
  setTimeout(() => { map.invalidateSize(); renderMarkers(); }, 100);
  window.addEventListener("resize", () => map.invalidateSize());

  // Also invalidate after tab switches (right panel resize)
  const obs = new ResizeObserver(() => map.invalidateSize());
  obs.observe(document.getElementById("map"));
}

function markerRadius(val){
  return Math.max(8, Math.min(60, Math.sqrt(val/100)*4.5));
}

function markerColor(p){
  if(ST.mode === "cat") return CAT[p.cat]?.color || "#fff";
  if(ST.mode === "risk"){
    const s = riskScore(p);
    if(s<=30) return "#10D97A";
    if(s<=55) return "#FFB020";
    if(s<=75) return "#FF4455";
    return "#CC0022";
  }
  if(ST.mode === "prob") return probColor(p.prob);
  if(ST.mode === "budget"){
    if(p.val > 20000) return "#FF4455";
    if(p.val > 5000) return "#FFB020";
    if(p.val > 500) return "#536253";
    return "#10D97A";
  }
  return CAT[p.cat]?.color || "#fff";
}

function filtered(){
  // Helper: extract first year number from p.year (handles "2030", "2030+", "Late 2025", "2032+", "2026")
  const yearOf = p => {
    const m = String(p.year||"").match(/(\d{4})/);
    return m ? parseInt(m[1]) : 9999;
  };
  const q = (ST.searchQuery||"").trim().toLowerCase();
  return P.filter(p => {
    if(!ST.cats.has(p.cat)) return false;
    if(ST.range === "sm" && p.val >= 500) return false;
    if(ST.range === "md" && (p.val < 500 || p.val >= 5000)) return false;
    if(ST.range === "lg" && (p.val < 5000 || p.val >= 20000)) return false;
    if(ST.range === "xl" && p.val < 20000) return false;
    if(ST.probFilter === "high" && p.prob < 70) return false;
    if(ST.probFilter === "med" && (p.prob < 40 || p.prob >= 70)) return false;
    if(ST.probFilter === "low" && p.prob >= 40) return false;
    // Timeline filter — show only projects opening on or before maxYear
    if(ST.maxYear < 2040 && yearOf(p) > ST.maxYear) return false;
    // Search filter — match project name, electorate, or status
    if(q){
      const hay = `${p.name||""} ${p.electorate||""} ${p.status||""} ${p.sub||""}`.toLowerCase();
      if(!hay.includes(q)) return false;
    }
    return true;
  });
}

// ─── Timeline slider handler ───
function onTimelineChange(year){
  ST.maxYear = parseInt(year);
  const lbl = document.getElementById("timeline-label");
  if(lbl){
    lbl.textContent = (ST.maxYear >= 2040) ? "All years" : `By end of ${ST.maxYear}`;
  }
  renderMarkers();
  buildProjList();
  // If price-projected mode is active, re-render the heatmap for new target year
  if(ST.showPrices && ST.priceMode === "projected"){
    renderPriceLayer();
    const titleEl = document.getElementById("price-legend-title");
    if(titleEl) titleEl.textContent = `PROJECTED UPLIFT BY ${ST.maxYear}`;
  }
}

// ─── Global search handler ───
function onSearch(){
  const input = document.getElementById("search-input");
  const q = (input?.value||"").trim();
  ST.searchQuery = q;
  const resBox = document.getElementById("search-results");
  if(!q){
    if(resBox) resBox.style.display = "none";
    renderMarkers();
    buildProjList();
    return;
  }
  const ql = q.toLowerCase();
  // Build result set: projects, federal seats, state seats, councils, suburbs
  const hits = [];
  P.forEach(p => {
    if(p.name.toLowerCase().includes(ql)){
      hits.push({type:"📍 Project", name:p.name, sub:`$${(p.val/1000).toFixed(1)}B · ${p.status}`, action:`selFromList(${p.id})`});
    }
  });
  FED_RESULTS_2025.forEach(e => {
    if(e.name.toLowerCase().includes(ql)){
      hits.push({type:"🏛 Federal", name:e.name, sub:`${e.party} ${e.margin.toFixed(1)}% · ${e.incumbent||"—"}`, action:`selElectorateByName('${e.name.replace(/'/g,"\\'")}',false)`});
    }
  });
  STATE_RESULTS_2023.forEach(e => {
    if(e.name.toLowerCase().includes(ql)){
      hits.push({type:"🗳 State", name:e.name, sub:`${e.party} ${e.margin.toFixed(1)}% · ${e.incumbent||"—"}`, action:`selElectorateByName('${e.name.replace(/'/g,"\\'")}',true)`});
    }
  });
  Object.entries(COUNCIL_DATA||{}).forEach(([name, m]) => {
    if(name.toLowerCase().includes(ql)){
      hits.push({type:"🏘 Council", name:name+" Council", sub:`${m.party||"?"} · ${m.mayor||"—"}`, action:`flyToCouncil('${name.replace(/'/g,"\\'")}')`});
    }
  });
  Object.keys(SUBURB_PRICES||{}).forEach(name => {
    if(name.toLowerCase().includes(ql)){
      const d = SUBURB_PRICES[name];
      hits.push({type:"📍 Suburb", name:_sfTitleCase(name), sub:`Median $${(d.median/1000).toFixed(0)}k · ${d.growth12mo>=0?'+':''}${d.growth12mo}% growth · click for report`, action:`openSuburbReport('${name.replace(/'/g,"\\'")}')`});
    }
  });
  // Limit to first 25 hits
  const limited = hits.slice(0, 25);
  if(resBox){
    if(limited.length === 0){
      resBox.innerHTML = `<div style="padding:8px;font-size:9px;color:var(--dim);text-align:center">No matches</div>`;
    } else {
      resBox.innerHTML = limited.map(h => `
        <div onclick='${h.action};document.getElementById("search-input").value="";document.getElementById("search-results").style.display="none";ST.searchQuery="";renderMarkers();buildProjList();'
             style="padding:5px 8px;border-bottom:1px solid var(--border);cursor:pointer;font-size:9px"
             onmouseover="this.style.background='#F5F7FA'" onmouseout="this.style.background='transparent'">
          <div style="display:flex;justify-content:space-between;gap:6px"><span style="color:var(--text);font-weight:700">${h.name}</span><span style="font-size:9px;color:var(--dim)">${h.type}</span></div>
          <div style="font-size:10px;color:var(--muted);margin-top:1px">${h.sub}</div>
        </div>`).join("");
    }
    resBox.style.display = "block";
  }
  renderMarkers();
  buildProjList();
}

// ─── Fly to council centroid ───
function toggleElecLegend(){
  const body = document.getElementById("elec-legend-body");
  const arrow = document.getElementById("elec-legend-arrow");
  if(!body) return;
  const open = body.style.display !== "none";
  body.style.display = open ? "none" : "block";
  if(arrow) arrow.style.transform = open ? "rotate(0deg)" : "rotate(180deg)";
}


