const PRESET_KEY = "sydney_infra_presets_v1";

function getPresets(){
  try { return JSON.parse(localStorage.getItem(PRESET_KEY) || "{}"); }
  catch { return {}; }
}
function savePresets(p){
  try { localStorage.setItem(PRESET_KEY, JSON.stringify(p)); }
  catch { console.warn("localStorage unavailable"); }
}
function snapshotFilters(){
  return {
    cats: [...ST.cats],
    range: ST.range,
    probFilter: ST.probFilter,
    maxYear: ST.maxYear,
    searchQuery: ST.searchQuery,
    showElec: ST.showElec, showState: ST.showState, showCouncils: ST.showCouncils,
    showImpactZones: ST.showImpactZones,
    showTravelTime: ST.showTravelTime,
    showBooths: ST.showBooths, showHeatmap: ST.showHeatmap,
    showPrices: ST.showPrices, priceMode: ST.priceMode,
    marginal: ST.marginal,
    marginalState: ST.marginalState,
  };
}
function applyFilters(snap){
  ST.cats = new Set(snap.cats || ["transport","housing","energy","water","other"]);
  ST.range = snap.range || "all";
  ST.probFilter = snap.probFilter || "all";
  ST.maxYear = snap.maxYear || 2040;
  ST.searchQuery = snap.searchQuery || "";
  ST.showElec = !!snap.showElec;
  ST.showState = !!snap.showState;
  ST.showCouncils = !!snap.showCouncils;
  ST.showImpactZones = !!snap.showImpactZones;
  ST.showTravelTime = !!snap.showTravelTime;
  ST.showBooths = !!snap.showBooths;
  ST.showHeatmap = !!snap.showHeatmap;
  ST.showPrices = !!snap.showPrices;
  ST.priceMode = snap.priceMode || "growth";
  ST.marginal = !!snap.marginal;
  ST.marginalState = !!snap.marginalState;
  // Reflect in UI
  document.querySelectorAll(".cat-btn").forEach(b => {
    const k = b.dataset.cat;
    if(ST.cats.has(k)){ b.classList.add("on"); document.getElementById(`cchk-${k}`)?.classList.add("on"); }
    else { b.classList.remove("on"); document.getElementById(`cchk-${k}`)?.classList.remove("on"); }
  });
  ["el","st","coun","iz","bt","heat","prices","tt","m","ms"].forEach(s => {
    const flag = {el:"showElec",st:"showState",coun:"showCouncils",iz:"showImpactZones",bt:"showBooths",heat:"showHeatmap",prices:"showPrices",tt:"showTravelTime",m:"marginal",ms:"marginalState"}[s];
    const btn = document.getElementById(`btn-${s}`);
    const chk = document.getElementById(`chk-${s}`);
    if(btn) ST[flag] ? btn.classList.add("on") : btn.classList.remove("on");
    if(chk) ST[flag] ? chk.classList.add("on") : chk.classList.remove("on");
  });
  const slider = document.getElementById("timeline-slider");
  if(slider) slider.value = ST.maxYear;
  const lbl = document.getElementById("timeline-label");
  if(lbl) lbl.textContent = (ST.maxYear >= 2040) ? "All years" : `By end of ${ST.maxYear}`;
  const search = document.getElementById("search-input");
  if(search) search.value = ST.searchQuery;
  const elecLeg = document.getElementById("elec-legend");
  if(elecLeg) elecLeg.style.display = (ST.showElec || ST.showState || ST.showCouncils) ? "block" : "none";
  const boothLeg = document.getElementById("booth-legend");
  if(boothLeg) boothLeg.style.display = ST.showBooths ? "block" : "none";
  const priceLeg = document.getElementById("price-legend");
  if(priceLeg) priceLeg.style.display = ST.showPrices ? "block" : "none";
  // Update price-mode pill state
  document.getElementById("pmode-growth")?.classList.toggle("on", ST.priceMode === "growth");
  document.getElementById("pmode-projected")?.classList.toggle("on", ST.priceMode === "projected");
  // Update price legend title for projected mode
  const titleEl = document.getElementById("price-legend-title");
  const subEl = document.getElementById("price-legend-sub");
  if(titleEl && subEl){
    if(ST.priceMode === "projected"){
      titleEl.textContent = `PROJECTED UPLIFT BY ${ST.maxYear}`;
      subEl.textContent = "Organic + infra-driven · cumulative %";
    } else {
      titleEl.textContent = "PROPERTY PRICE GROWTH";
      subEl.textContent = "12-month change · Cotality / Domain Sep 2025";
    }
  }
  renderMarkers();
  buildProjList();
}

