function openPriceProjection(){
  const targetYear = ST.maxYear;
  const projections = Object.keys(SUBURB_PRICES)
    .map(n => projectedPriceUplift(n, targetYear))
    .filter(p => p)
    .sort((a, b) => b.total - a.total);
  const top = projections.slice(0, 12);
  const bottom = projections.slice(-6).reverse();
  const formatRow = pr => {
    const pct = pr.total;
    const col = priceGrowthColour(pct);
    const display = pr.suburb.split(" ").map(w => w[0] + w.slice(1).toLowerCase()).join(" ");
    return `<div style="padding:6px 8px;border-bottom:1px solid var(--border);display:grid;grid-template-columns:1fr auto auto;gap:8px;align-items:center;font-size:9px">
      <div>
        <div style="color:var(--text);font-weight:700">${display}</div>
        <div style="font-size:9px;color:var(--dim);margin-top:1px">$${(pr.base.median/1000).toFixed(0)}k → $${(pr.medianTarget/1000).toFixed(0)}k</div>
      </div>
      <div style="text-align:right">
        <div style="color:#7A9AB8;font-size:8px">+${pr.organic.toFixed(1)}%</div>
        <div style="color:#10D97A;font-size:8px">+${pr.infra.toFixed(1)}%</div>
      </div>
      <div style="color:${col};font-weight:700;font-size:11px;font-family:var(--mono);min-width:55px;text-align:right">+${pct.toFixed(1)}%</div>
    </div>`;
  };
  const html = `
    <div style="padding:12px 16px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between">
      <div>
        <div style="font-size:13px;font-weight:700;color:var(--text)">📈 Price Projection by ${targetYear}</div>
        <div style="font-size:9px;color:var(--dim);margin-top:2px">Total uplift = organic growth (capped at 6%/yr) + Σ(probability × infra uplift × delivery curve). Use timeline slider to change target year.</div>
      </div>
      <button onclick="closeModal()" style="background:none;border:1px solid var(--border2);color:var(--dim);padding:3px 8px;cursor:pointer;border-radius:3px;font-size:11px">✕</button>
    </div>
    <div style="padding:10px 16px;max-height:75vh;overflow-y:auto">
      <div style="display:grid;grid-template-columns:auto auto auto;gap:6px 12px;font-size:10px;color:var(--dim);padding:0 8px 4px;text-transform:uppercase;letter-spacing:.06em">
        <span>Suburb · Price now → ${targetYear}</span>
        <span style="text-align:right">Organic / Infra</span>
        <span style="text-align:right">Total</span>
      </div>
      <div style="font-size:10px;color:#10D97A;font-weight:700;margin:8px 8px 4px;letter-spacing:.06em">▲ TOP 12 PROJECTED GAINERS</div>
      ${top.map(formatRow).join("")}
      <div style="font-size:10px;color:#FF4455;font-weight:700;margin:14px 8px 4px;letter-spacing:.06em">▼ SLOWEST PROJECTED MOVERS</div>
      ${bottom.map(formatRow).join("")}
      <div style="margin-top:12px;padding:8px 10px;background:var(--panel);border-radius:4px;border-left:2px solid var(--amber);font-size:10px;color:var(--muted);line-height:1.5">
        <b style="color:var(--amber)">Method:</b> For each affecting project, contribution = property uplift × probability × delivery curve. Curve: 10% baked in 3 years before opening, 60% at opening year, 100% from 5 years after. <br><br>Empirical basis: Domain (Oct 2025) found Sydney Metro NW houses within 400m sold +16.6% above 2-3km comparables; University of Sydney (2019) found up to 15% growth premium within 800m. Delivery curve calibrated to observed Crows Nest, Barangaroo, Bella Vista trajectories.<br><br><a onclick="closeModal();setTimeout(openSourcesModal,100)" style="color:var(--blue);cursor:pointer;text-decoration:underline">📚 Read full sources & methodology →</a>
      </div>
    </div>`;
  openModal(html);
}



function flyToCouncil(name){
  if(typeof COUNCILS_GEOJSON === 'undefined') return;
  const feat = COUNCILS_GEOJSON.features.find(f => f.properties.councilName === name);
  if(!feat) return;
  // Compute centroid of bounding box
  const bounds = L.geoJSON(feat).getBounds();
  // Auto-enable councils layer
  if(!ST.showCouncils){
    ST.showCouncils = true;
    document.getElementById("btn-coun")?.classList.add("on");
    document.getElementById("chk-coun")?.classList.add("on");
    const leg = document.getElementById("elec-legend");
    if(leg) leg.style.display = "block";
    renderMarkers();
  }
  map.flyToBounds(bounds, {duration:1.0, padding:[20,20]});
}

