let _amenityLayers = [];
function renderAmenities(){
  // Clear existing
  _amenityLayers.forEach(l => map.removeLayer(l));
  _amenityLayers = [];
  if(typeof AMENITIES === "undefined") return;

  // Drop-pin icon factory. All amenity types share the same teardrop SHAPE;
  // colour and inner emoji distinguish hospital/uni/school/station. Keeping
  // shape constant avoids the "distinct shape per type" pattern explicitly
  // ruled out in handoff, while still making amenities visually distinct from
  // project circle markers.
  const amenityPin = (color, emoji) => {
    // Pin dimensions: 26 wide × 34 tall; anchor at bottom-centre (tip on lat/lon).
    // SVG path is a teardrop with rounded head and pointed tail.
    const html = `
<svg viewBox="0 0 26 34" width="26" height="34" xmlns="http://www.w3.org/2000/svg" style="filter:drop-shadow(0 2px 2.5px rgba(0,0,0,0.45))">
  <path d="M13 1 C6.4 1 1.4 6 1.4 12.4 C1.4 21 13 33 13 33 C13 33 24.6 21 24.6 12.4 C24.6 6 19.6 1 13 1 Z"
        fill="${color}" stroke="#ffffff" stroke-width="1.6" stroke-linejoin="round"/>
  <circle cx="13" cy="12.4" r="6.6" fill="rgba(255,255,255,0.94)"/>
</svg>
<div class="ico">${emoji}</div>`;
    return L.divIcon({
      className: "amenity-pin",
      html: html,
      iconSize: [26, 34],
      iconAnchor: [13, 33],     // pin tip sits exactly on the lat/lon
      tooltipAnchor: [0, -28],  // tooltip floats above the pin head
      popupAnchor: [0, -30],
    });
  };

  const renderSet = (items, conf) => {
    const icon = amenityPin(conf.color, conf.icon);
    items.forEach(it => {
      const m = L.marker([it.lat, it.lon], {
        icon: icon,
        pane: "markersPane",
        riseOnHover: true,
        keyboard: false,
      }).addTo(map);
      const label = `<div style="font-family:var(--mono);font-size:10px;padding:5px 7px;min-width:160px">
        <div style="color:${conf.color};font-weight:700;font-size:11px">${conf.icon} ${it.name}</div>
        ${conf.detail(it)}
      </div>`;
      m.bindTooltip(label, {className:"stn-tooltip", direction:"top"});
      _amenityLayers.push(m);
    });
  };

  if(ST.showHospitals) renderSet(AMENITIES.hospitals, {
    color:"#FF6677", icon:"🏥",
    detail: it => `<div style="font-size:10px;color:var(--muted);margin-top:2px">${it.beds} beds</div>`,
  });
  if(ST.showUnis) renderSet(AMENITIES.universities, {
    color:"#5DE0FF", icon:"🎓",
    detail: it => `<div style="font-size:10px;color:var(--muted);margin-top:2px">${it.students.toLocaleString()} students</div>`,
  });
  if(ST.showSchools) renderSet(AMENITIES.topSchools, {
    color:"#FFC444", icon:"📚",
    detail: it => `<div style="font-size:10px;color:var(--muted);margin-top:2px">${it.type}</div>`,
  });
  if(ST.showStations) renderSet(AMENITIES.trainStations, {
    color:"#3DDB8E", icon:"🚆",
    detail: it => `<div style="font-size:10px;color:var(--muted);margin-top:2px">Lines: ${it.lines}</div>`,
  });
}

function renderHeatmap(){
  if(_heatmapLayer){
    map.removeLayer(_heatmapLayer);
    _heatmapLayer = null;
  }
  if(!ST.showHeatmap) return;
  // Group projects by 0.02 deg grid (~2km cells)
  const grid = {};
  filtered().forEach(p => {
    if(!p.lat || !p.lon) return;
    const gx = Math.round(p.lat / 0.02) * 0.02;
    const gy = Math.round(p.lon / 0.02) * 0.02;
    const k = `${gx},${gy}`;
    if(!grid[k]) grid[k] = {lat:0, lon:0, count:0, value:0, projects:[]};
    grid[k].lat += p.lat;
    grid[k].lon += p.lon;
    grid[k].count++;
    grid[k].value += (p.val||0);
    grid[k].projects.push(p);
  });
  // Render as circles sized by total value, coloured by count
  const cells = Object.values(grid).filter(c => c.count >= 2);  // hide singletons
  if(cells.length === 0) return;
  const layerGroup = L.layerGroup();
  cells.forEach(c => {
    const lat = c.lat / c.count;
    const lon = c.lon / c.count;
    // Radius scaled by sqrt of total value
    const r = Math.max(15, Math.min(50, Math.sqrt(c.value) * 0.4));
    // Colour intensity by count
    const intensity = Math.min(1, c.count / 6);
    const col = `rgba(255, 139, 69, ${0.18 + intensity * 0.35})`;
    const projList = c.projects
      .sort((a,b) => b.val - a.val)
      .slice(0, 5)
      .map(p => `• ${p.name} ($${(p.val/1000).toFixed(1)}B)`)
      .join("<br>");
    const more = c.projects.length > 5 ? `<br><span style="color:var(--dim)">+${c.projects.length-5} more</span>` : "";
    const circle = L.circleMarker([lat, lon], {
      radius: r, color: "#FF8B45", weight: 1.5, opacity: 0.7,
      fillColor: col, fillOpacity: 1
    });
    circle.bindTooltip(`<div style="font-family:var(--mono);font-size:10px;padding:6px 8px;min-width:200px">
      <div style="color:#FF8B45;font-weight:700;font-size:11px;margin-bottom:4px">🔥 ${c.count} projects clustered</div>
      <div style="color:#D4E4F4;font-weight:700;font-size:10px;margin-bottom:5px">$${(c.value/1000).toFixed(1)}B total value</div>
      <div style="font-size:9px;color:var(--muted);line-height:1.5">${projList}${more}</div>
    </div>`, {className:"stn-tooltip", sticky:true});
    layerGroup.addLayer(circle);
  });
  layerGroup.addTo(map);
  _heatmapLayer = layerGroup;
}


// ── TRAVEL TIME TO CBD ──
// Per-suburb AM-peak rail+walk minutes to Town Hall. Methodology:
//   1. Compute the polygon centroid.
//   2. Find nearest station from CBD_STATIONS below (haversine).
//   3. walkMin = min(25, distance_km × 60/4.5)   // 4.5 km/h pedestrian
//   4. railMin = station.m  (typical AM-peak time to Town Hall, ±2 min)
//   5. minutes = round(walkMin + railMin)
// Source data: public TfNSW timetables (sydneytrains.info / transportnsw.info).
// Includes Sydney Metro M1 (Tallawong-Sydenham, operational from 2024) and a
// small set of virtual bus-interchange anchors for non-rail suburbs (Eastern
// Beaches, Northern Beaches, Inner West harbour-side).

const TRAVEL_BANDS = [
  {max:15,  color:"#C8E3C8", label:"≤15 min"},
  {max:30,  color:"#7FC97F", label:"15–30 min"},
  {max:45,  color:"#2E8B8A", label:"30–45 min"},
  {max:60,  color:"#3D4A87", label:"45–60 min"},
  {max:999, color:"#1A1A1A", label:">60 min"},
];

function _haversineKm(la1, lo1, la2, lo2){
  const R = 6371;
  const r1 = la1 * Math.PI/180, r2 = la2 * Math.PI/180;
  const dr = (la2-la1) * Math.PI/180, dl = (lo2-lo1) * Math.PI/180;
  const a = Math.sin(dr/2)**2 + Math.cos(r1)*Math.cos(r2)*Math.sin(dl/2)**2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

function _polygonCentroid(feat){
  // Coords are nested [lng,lat] arrays. Walk down to the leaves and average.
  const pts = [];
  const walk = (a) => {
    if(typeof a[0] === "number" && a.length >= 2) pts.push(a);
    else if(Array.isArray(a)) a.forEach(walk);
  };
  if(!feat || !feat.geometry || !feat.geometry.coordinates) return null;
  walk(feat.geometry.coordinates);
  if(!pts.length) return null;
  let la = 0, lo = 0;
  for(const [lng, lat] of pts){ la += lat; lo += lng; }
  return [la / pts.length, lo / pts.length];
}

function _cbdMinutes(la, lo){
  let best = null;
  for(const st of CBD_STATIONS){
    const km = _haversineKm(la, lo, st.la, st.lo);
    if(!best || km < best.km) best = { st: st, km: km };
  }
  if(!best) return null;
  const walkMin = Math.min(25, best.km * (60/4.5));   // cap at 25 min
  return { mins: Math.round(walkMin + best.st.m), station: best.st.n, walkMin: Math.round(walkMin), railMin: best.st.m };
}

function _bandForMinutes(min){
  for(const b of TRAVEL_BANDS) if(min <= b.max) return b;
  return TRAVEL_BANDS[TRAVEL_BANDS.length-1];
}

let _travelLayer = null;
function renderTravelTimeLayer(){
  if(_travelLayer){
    map.removeLayer(_travelLayer);
    _travelLayer = null;
  }
  if(!ST.showTravelTime) return;
  if(typeof SUBURBS_GEOJSON === "undefined") return;

  const features = SUBURBS_GEOJSON.features || [];
  const sublayers = [];
  features.forEach(feat => {
    const c = _polygonCentroid(feat);
    if(!c) return;
    const r = _cbdMinutes(c[0], c[1]);
    if(!r) return;
    const band = _bandForMinutes(r.mins);
    const name = (feat.properties && feat.properties.name) || "";
    const display = name.split(" ").map(w => w[0] + w.slice(1).toLowerCase()).join(" ");
    const poly = L.geoJSON(feat, {
      pane: "travelPane",
      style: { color: band.color, weight: 0.4, opacity: 0.65, fillColor: band.color, fillOpacity: 0.5 }
    });
    poly.bindTooltip(
      `<b>${display}</b><br>${r.mins} min to Town Hall<br>` +
      `<span style="opacity:.7">via ${r.station} · walk ${r.walkMin} + rail ${r.railMin}</span>`,
      { sticky: true, className: "stn-tooltip" }
    );
    sublayers.push(poly);
  });
  if(sublayers.length){
    _travelLayer = L.layerGroup(sublayers).addTo(map);
  }
}

