// ─── INFRASTRUCTURE SNOWFLAKE — 5-axis suburb score (1-5 per axis) ───
//
// Each axis scored 1 (poor) → 5 (excellent). All "higher = better outlook":
//
//   POLITICAL RISK    — high score = LOW risk = safe (seat margins + project
//                       politicalRisk field, weighted)
//   BUDGET COMMITMENT — weighted-avg (prob × status-multiplier) across affecting
//                       projects, weighted by project val
//   SPEND CONC.       — $ attributable to this suburb (sum project.val ÷ catch.
//                       size). Static thresholds in $M.
//   PIPELINE MOMENTUM — activeness × proximity × probability weighted by val.
//                       Rewards "under construction" projects opening within
//                       ~5yr with high prob.
//   PROJECT DIVERSITY — count of distinct project.cat values in catchment
//                       (transport, housing, energy, water, other)
//
// All five draw from the existing project register P + PROJECT_IMPACT.
// No external datasets. Methodology in Sources & Methodology modal.

function _pointInRing(pt, ring){
  let inside = false;
  const x = pt[0], y = pt[1];
  for(let i=0, j=ring.length-1; i<ring.length; j=i++){
    const xi = ring[i][0], yi = ring[i][1];
    const xj = ring[j][0], yj = ring[j][1];
    if(((yi>y) !== (yj>y)) && (x < (xj-xi)*(y-yi)/(yj-yi) + xi)) inside = !inside;
  }
  return inside;
}
function _pointInFeature(pt, feat){
  const g = feat && feat.geometry;
  if(!g) return false;
  if(g.type === "Polygon"){
    if(!_pointInRing(pt, g.coordinates[0])) return false;
    for(let h=1; h<g.coordinates.length; h++) if(_pointInRing(pt, g.coordinates[h])) return false;
    return true;
  }
  if(g.type === "MultiPolygon"){
    for(const poly of g.coordinates){
      if(!_pointInRing(pt, poly[0])) continue;
      let inHole = false;
      for(let h=1; h<poly.length; h++) if(_pointInRing(pt, poly[h])){ inHole = true; break; }
      if(!inHole) return true;
    }
  }
  return false;
}
function _findContainingElec(lngLat, gj, keys){
  if(!gj || !gj.features) return null;
  for(const feat of gj.features){
    if(_pointInFeature(lngLat, feat)){
      const p = feat.properties || {};
      for(const k of keys){ if(p[k]) return String(p[k]); }
    }
  }
  return null;
}
function _suburbCentroid(name){
  if(typeof SUBURBS_GEOJSON === "undefined") return null;
  const upper = (name||"").toUpperCase();
  const feat = (SUBURBS_GEOJSON.features||[]).find(
    f => (f.properties && (f.properties.name||"")).toUpperCase() === upper
  );
  return feat ? _polygonCentroid(feat) : null;  // [lat, lng]
}

// ─── Per-axis scoring (5-axis system) ───

function _scorePolitical(suburb){
  // Composite: 60% per-project politicalRisk (val-weighted), 40% containing seat margins
  let projs = [];
  try { projs = projectsAffectingSuburb(suburb) || []; } catch(e) {}

  // Component A — average per-project politicalRisk (0-100, HIGHER=more risk)
  let projRiskAvg = null;
  if(projs.length > 0){
    let sumW = 0, sumWeighted = 0;
    projs.forEach(({project}) => {
      const w = project.val || 1;
      sumW += w;
      sumWeighted += (project.politicalRisk != null ? project.politicalRisk : 50) * w;
    });
    projRiskAvg = sumWeighted / sumW;
  }
  let projScore = 3;
  if(projRiskAvg !== null){
    if(projRiskAvg < 20)       projScore = 5;
    else if(projRiskAvg < 35)  projScore = 4;
    else if(projRiskAvg < 55)  projScore = 3;
    else if(projRiskAvg < 75)  projScore = 2;
    else                       projScore = 1;
  }

  // Component B — containing seat margins (point-in-polygon)
  const c = _suburbCentroid(suburb);
  let seatScore = 3, fedName = null, stateName = null, fedMargin = null, stateMargin = null;
  if(c){
    const lngLat = [c[1], c[0]];
    if(typeof FED_BOUNDARIES_GEOJSON !== "undefined"){
      fedName = _findContainingElec(lngLat, FED_BOUNDARIES_GEOJSON, ["districtName","name","NAME"]);
    }
    if(typeof STATE_BOUNDARIES_GEOJSON !== "undefined"){
      stateName = _findContainingElec(lngLat, STATE_BOUNDARIES_GEOJSON, ["districtName","name","NAME"]);
    }
    if(typeof ELECTORATES !== "undefined"){
      if(fedName){
        const e = ELECTORATES.find(x => x.level==="Federal"
          && (x.name||"").toLowerCase() === fedName.toLowerCase());
        if(e) fedMargin = Math.abs(e.margin || 0);
      }
      if(stateName){
        const e = ELECTORATES.find(x => x.level==="State"
          && (x.name||"").toLowerCase() === stateName.toLowerCase());
        if(e) stateMargin = Math.abs(e.margin || 0);
      }
    }
    const m2s = m => m===null ? 3 : m<2 ? 1 : m<5 ? 2 : m<8 ? 3 : m<12 ? 4 : 5;
    seatScore = (m2s(fedMargin) + m2s(stateMargin)) / 2;
  }

  const blended = projScore * 0.6 + seatScore * 0.4;
  const score = Math.max(1, Math.min(5, Math.round(blended)));

  const seatStr = (fedName||stateName)
    ? `Fed: ${fedName||"—"}${fedMargin!==null?` (${fedMargin.toFixed(1)}%)`:""}, State: ${stateName||"—"}${stateMargin!==null?` (${stateMargin.toFixed(1)}%)`:""}`
    : "Seats: unknown";
  const projStr = projs.length === 0
    ? "no projects in catchment"
    : `${projs.length} project${projs.length>1?"s":""}, avg politicalRisk ${(projRiskAvg||0).toFixed(0)}/100`;
  return { score, detail: `${projStr} · ${seatStr}` };
}

function _scoreBudget(suburb){
  // Cost-weighted commitment = avg(prob × statusBoost) weighted by project.val
  let projs = [];
  try { projs = projectsAffectingSuburb(suburb) || []; } catch(e) {}
  if(projs.length === 0) return { score: 1, detail: "No active projects in catchment" };

  const statusBoost = (status) => {
    if(!status) return 0.80;
    const t = status.toLowerCase();
    if(t.includes("operational"))         return 1.10;
    if(t.includes("under construction"))  return 1.10;
    if(t.includes("opening"))             return 1.05;
    if(t.includes("procurement"))         return 0.90;
    if(t.includes("planning"))            return 0.70;
    if(t.includes("concept"))             return 0.50;
    return 0.80;
  };

  let sumW = 0, sumWeighted = 0;
  projs.forEach(({project}) => {
    const w = project.val || 1;
    const commit = (project.prob || 50) * statusBoost(project.status);
    sumW += w;
    sumWeighted += commit * w;
  });
  const avgCommit = sumWeighted / sumW;  // 0-110ish

  let score;
  if(avgCommit > 90)       score = 5;
  else if(avgCommit > 70)  score = 4;
  else if(avgCommit > 50)  score = 3;
  else if(avgCommit > 30)  score = 2;
  else                     score = 1;

  return {
    score,
    detail: `${projs.length} project${projs.length>1?"s":""}, cost-weighted commitment ${avgCommit.toFixed(0)}/100`
  };
}

function _scoreSpend(suburb){
  // Sum of (project.val ÷ catchmentSuburbs.length) across affecting projects
  let projs = [];
  try { projs = projectsAffectingSuburb(suburb) || []; } catch(e) {}
  if(projs.length === 0) return { score: 1, detail: "No projects in catchment" };

  let totalSpend = 0;  // $M attributable to this suburb
  projs.forEach(({project, impact}) => {
    const catchSize = (impact.catchmentSuburbs || []).length || 1;
    totalSpend += (project.val || 0) / catchSize;
  });

  let score;
  if(totalSpend > 3000)      score = 5;   // $3B+ attributable
  else if(totalSpend > 1500) score = 4;   // $1.5-3B
  else if(totalSpend > 500)  score = 3;   // $500M-1.5B
  else if(totalSpend > 100)  score = 2;   // $100-500M
  else                       score = 1;

  const fmt = totalSpend >= 1000
    ? `$${(totalSpend/1000).toFixed(1)}B`
    : `$${totalSpend.toFixed(0)}M`;
  return {
    score,
    detail: `~${fmt} attributable spend across ${projs.length} project${projs.length>1?"s":""}`
  };
}

function _scoreMomentum(suburb){
  // Activeness × proximity × probability, weighted by val
  let projs = [];
  try { projs = projectsAffectingSuburb(suburb) || []; } catch(e) {}
  if(projs.length === 0) return { score: 1, detail: "No projects in catchment" };

  const NOW = 2026;
  let sumW = 0, sumMom = 0;
  projs.forEach(({project}) => {
    const w = project.val || 1;
    const yr = parseInt(project.year) || (NOW + 10);
    const yearsOut = yr - NOW;

    const t = (project.status || "").toLowerCase();
    let activeness;
    if(t.includes("under construction"))  activeness = 1.00;
    else if(t.includes("opening"))        activeness = 0.95;
    else if(t.includes("procurement"))    activeness = 0.75;
    else if(t.includes("planning"))       activeness = 0.50;
    else if(t.includes("concept"))        activeness = 0.25;
    else if(t.includes("operational"))    activeness = 0.30; // delivered, low forward momentum
    else                                  activeness = 0.50;

    let proximity;
    if(yearsOut <= 0)         proximity = 0.40;
    else if(yearsOut <= 3)    proximity = 1.00;
    else if(yearsOut <= 7)    proximity = 0.75;
    else if(yearsOut <= 15)   proximity = 0.50;
    else                      proximity = 0.25;

    const probFrac = (project.prob || 50) / 100;
    const momentum = activeness * proximity * probFrac;
    sumW += w;
    sumMom += momentum * w;
  });
  const avgMom = sumMom / sumW;  // 0-1

  let score;
  if(avgMom > 0.60)       score = 5;
  else if(avgMom > 0.42)  score = 4;
  else if(avgMom > 0.27)  score = 3;
  else if(avgMom > 0.13)  score = 2;
  else                    score = 1;

  return {
    score,
    detail: `Momentum index ${(avgMom*100).toFixed(0)}/100 (status × horizon × probability)`
  };
}

function _scoreDiversity(suburb){
  // Count of distinct project.cat values in catchment
  let projs = [];
  try { projs = projectsAffectingSuburb(suburb) || []; } catch(e) {}
  if(projs.length === 0) return { score: 1, detail: "No projects in catchment" };

  const cats = new Set();
  projs.forEach(({project}) => { if(project.cat) cats.add(project.cat); });
  const n = cats.size;
  const score = n >= 5 ? 5 : n;

  return {
    score,
    detail: `${n} project type${n!==1?"s":""}: ${[...cats].join(", ") || "—"}`
  };
}

function computeSnowflake(suburb){
  return {
    suburb: suburb,
    political: _scorePolitical(suburb),
    budget:    _scoreBudget(suburb),
    spend:     _scoreSpend(suburb),
    momentum:  _scoreMomentum(suburb),
    diversity: _scoreDiversity(suburb)
  };
}

// ─── SVG render (pentagon, 5 axes) ───

function renderSnowflakeSVG(sf){
  const cx = 215, cy = 200, rMax = 130, levels = 5;
  const axes = [
    { key:"political", label:"POLITICAL", angle:-90  },
    { key:"budget",    label:"BUDGET",    angle:-18  },
    { key:"momentum",  label:"MOMENTUM",  angle: 54  },
    { key:"diversity", label:"DIVERSITY", angle:126  },
    { key:"spend",     label:"SPEND",     angle:198  }
  ];
  const polar = (r, deg) => {
    const rad = deg * Math.PI / 180;
    return [cx + r*Math.cos(rad), cy + r*Math.sin(rad)];
  };

  // Concentric pentagons
  let bg = "";
  for(let lvl=1; lvl<=levels; lvl++){
    const r = (lvl/levels) * rMax;
    const pts = axes.map(a => polar(r, a.angle).map(v => v.toFixed(1)).join(",")).join(" ");
    bg += `<polygon points="${pts}" fill="none" stroke="#4a5a6e" stroke-width="0.5" opacity="${(0.22 + 0.07*lvl).toFixed(2)}"/>`;
  }

  // Spokes
  let spokes = "";
  axes.forEach(a => {
    const [x,y] = polar(rMax, a.angle);
    spokes += `<line x1="${cx}" y1="${cy}" x2="${x.toFixed(1)}" y2="${y.toFixed(1)}" stroke="#4a5a6e" stroke-width="0.5" opacity="0.55"/>`;
  });

  // Score polygon
  const pts = axes.map(a => {
    const r = (sf[a.key].score / levels) * rMax;
    return polar(r, a.angle).map(v => v.toFixed(1)).join(",");
  }).join(" ");
  const poly = `<polygon points="${pts}" fill="#FFC444" fill-opacity="0.30" stroke="#FFC444" stroke-width="2" stroke-linejoin="round"/>`;

  // Score dots
  let dots = "";
  axes.forEach(a => {
    const r = (sf[a.key].score / levels) * rMax;
    const [x,y] = polar(r, a.angle);
    dots += `<circle cx="${x.toFixed(1)}" cy="${y.toFixed(1)}" r="4.5" fill="#FFC444" stroke="#1A2535" stroke-width="2"/>`;
  });

  // Axis labels
  let labels = "";
  axes.forEach(a => {
    const [x,y] = polar(rMax + 22, a.angle);
    const cos = Math.cos(a.angle * Math.PI/180);
    const sin = Math.sin(a.angle * Math.PI/180);
    let anchor = "middle";
    if(cos > 0.3) anchor = "start";
    else if(cos < -0.3) anchor = "end";
    const dy = sin > 0.3 ? 12 : (sin < -0.3 ? -2 : 4);
    labels += `<text x="${x.toFixed(1)}" y="${(y+dy).toFixed(1)}" text-anchor="${anchor}" fill="#F1F5FA" font-family="Inter,sans-serif" font-size="10.5" font-weight="700" letter-spacing="0.6">${a.label}</text>`;
  });

  return `<svg viewBox="0 0 430 370" width="100%" height="100%" style="max-width:400px;display:block;margin:0 auto">
    <g>${bg}</g>
    <g>${spokes}</g>
    ${poly}
    <g>${dots}</g>
    <g>${labels}</g>
  </svg>`;
}

function _sfRowsHTML(sf){
  const rows = [
    { key:"political", label:"🗳 Political risk",      hint:"high = safer" },
    { key:"budget",    label:"💰 Budget commitment",   hint:"high = funded" },
    { key:"spend",     label:"💵 Spend concentration", hint:"high = $ flowing in" },
    { key:"momentum",  label:"🚧 Pipeline momentum",   hint:"high = active" },
    { key:"diversity", label:"🔀 Project diversity",   hint:"high = mixed" }
  ];
  return rows.map(a => {
    const x = sf[a.key];
    const w = (x.score/5) * 100;
    return `<div style="display:grid;grid-template-columns:135px 95px 1fr;gap:10px;padding:7px 0;border-bottom:1px solid var(--border);align-items:center">
      <div>
        <div style="font-size:11px;color:var(--text);font-weight:600">${a.label}</div>
        <div style="font-size:9px;color:var(--dim);margin-top:1px">${a.hint}</div>
      </div>
      <div style="display:flex;align-items:center;gap:6px">
        <div style="flex:1;height:7px;background:#2a3a4e;border-radius:2px;overflow:hidden">
          <div style="width:${w}%;height:100%;background:#FFC444"></div>
        </div>
        <div style="font-family:var(--mono);font-size:11px;font-weight:700;color:#FFC444;min-width:26px;text-align:right">${x.score}<span style="color:var(--dim);font-weight:400">/5</span></div>
      </div>
      <div style="font-size:10px;color:var(--muted);line-height:1.4">${x.detail}</div>
    </div>`;
  }).join("");
}

function _sfTitleCase(name){
  return name.split(" ").map(w => w ? w[0] + w.slice(1).toLowerCase() : w).join(" ");
}

function _sfHeadlineHTML(sf){
  const avg = (sf.political.score + sf.budget.score + sf.spend.score + sf.momentum.score + sf.diversity.score) / 5;
  const grade = avg >= 4.0 ? "A" : avg >= 3.0 ? "B" : avg >= 2.0 ? "C" : "D";
  const color = avg >= 4.0 ? "#3DD68C" : avg >= 3.0 ? "#FFC444" : avg >= 2.0 ? "#FF9966" : "#FF6B6B";

  // Top projects affecting the suburb (for context)
  let projs = [];
  try { projs = projectsAffectingSuburb(sf.suburb) || []; } catch(e) {}
  // Sort by val descending, take top 3
  projs.sort((a,b) => (b.project.val||0) - (a.project.val||0));
  const top = projs.slice(0, 3).map(p => p.project.name).join(" · ");
  const projLine = projs.length === 0
    ? '<span style="color:var(--dim)">No projects in catchment</span>'
    : `<span style="color:var(--muted)">${projs.length} project${projs.length>1?"s":""}:</span> ${top}${projs.length>3?` <span style="color:var(--dim)">+${projs.length-3} more</span>`:""}`;

  return `<div style="display:flex;justify-content:space-between;align-items:center;padding:14px 16px;background:var(--panel2);border-radius:6px;margin-bottom:14px;border:1px solid var(--border)">
    <div style="min-width:0;flex:1">
      <div style="font-size:18px;font-weight:700;color:var(--text);letter-spacing:0.5px">${_sfTitleCase(sf.suburb)}</div>
      <div style="font-size:9px;color:var(--dim);margin-top:2px;letter-spacing:1px">INFRASTRUCTURE SCORE</div>
      <div style="font-size:10px;color:var(--muted);margin-top:8px;line-height:1.4;overflow:hidden;text-overflow:ellipsis">${projLine}</div>
    </div>
    <div style="text-align:right;margin-left:12px">
      <div style="font-size:32px;font-weight:700;color:${color};font-family:var(--mono);line-height:1">${avg.toFixed(1)}<span style="font-size:14px;color:var(--dim);font-weight:400">/5</span></div>
      <div style="font-size:10px;color:${color};margin-top:3px;letter-spacing:2px;font-weight:700">GRADE ${grade}</div>
    </div>
  </div>`;
}

// ─── Search UI (custom dropdown, not native datalist) ───

function openSnowflakeModal(initialSuburb){
  const initial = (initialSuburb || "PARRAMATTA").toUpperCase();
  const start = SUBURB_PRICES[initial] ? initial : Object.keys(SUBURB_PRICES).sort()[0];
  const sf = computeSnowflake(start);

  const html = `
    <div style="padding:14px 22px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">
      <div>
        <div style="font-size:14px;font-weight:700;color:var(--text)">🔬 Infrastructure Snowflake</div>
        <div style="font-size:11px;color:var(--dim);margin-top:2px">5-axis suburb score · pure infrastructure exposure (Value, Yield, etc. live on Domain/CoreLogic)</div>
      </div>
      <button onclick="closeModal()" style="background:none;border:1px solid var(--border2);color:var(--dim);padding:4px 10px;cursor:pointer;border-radius:3px;font-size:12px">✕</button>
    </div>

    <div style="padding:12px 22px;background:var(--panel2);border-bottom:1px solid var(--border);position:relative">
      <div style="display:flex;align-items:center;gap:10px">
        <span style="font-size:11px;color:var(--dim);font-weight:600">Suburb:</span>
        <div style="flex:1;position:relative">
          <input id="sf-search" type="text" value="${_sfTitleCase(start)}" placeholder="Type to filter…" autocomplete="off"
            oninput="sfFilterDropdown()" onfocus="sfFilterDropdown()" onkeydown="sfHandleKey(event)" onblur="setTimeout(sfHideDropdown, 180)"
            style="width:100%;box-sizing:border-box;background:var(--panel);border:1px solid var(--border2);color:var(--text);padding:7px 10px;border-radius:3px;font-family:var(--font);font-size:12px;outline:none"
            onkeyup="this.style.borderColor='#FFC444'" onmouseout="this.style.borderColor='var(--border2)'">
          <div id="sf-dropdown" style="display:none;position:absolute;top:100%;left:0;right:0;margin-top:2px;background:var(--panel);border:1px solid var(--border2);border-radius:3px;max-height:240px;overflow-y:auto;z-index:99999;box-shadow:0 4px 12px rgba(15,23,42,0.12)"></div>
        </div>
      </div>
    </div>

    <div style="padding:14px 22px;max-height:75vh;overflow-y:auto">
      <div id="sf-headline">${_sfHeadlineHTML(sf)}</div>
      <div id="sf-chart" style="margin-bottom:14px">${renderSnowflakeSVG(sf)}</div>
      <div id="sf-scores">${_sfRowsHTML(sf)}</div>
      <div style="margin-top:14px;padding:10px 12px;background:var(--panel2);border-radius:4px;border-left:3px solid var(--blue);font-size:10px;color:var(--muted);line-height:1.5">
        Five-axis equal-weight score. All axes derived from this dashboard's project register (no external feeds). <b>Higher score is always better outlook.</b> <a href="#" onclick="event.preventDefault(); closeModal(); setTimeout(openSourcesModal, 120)" style="color:var(--blue);text-decoration:underline">Full methodology →</a>
      </div>
    </div>`;

  openModal(html);
}

function sfFilterDropdown(){
  const input = document.getElementById("sf-search");
  const dropdown = document.getElementById("sf-dropdown");
  if(!input || !dropdown) return;
  const q = (input.value || "").trim().toUpperCase();
  const all = Object.keys(SUBURB_PRICES).sort();
  let matches;
  if(q === ""){
    matches = all.slice(0, 10);
  } else {
    const starts = all.filter(k => k.startsWith(q));
    const contains = all.filter(k => !k.startsWith(q) && k.includes(q));
    matches = [...starts, ...contains].slice(0, 10);
  }
  if(matches.length === 0){
    dropdown.innerHTML = `<div style="padding:8px 12px;font-size:11px;color:var(--dim);font-style:italic">No suburbs match "${q.toLowerCase()}"</div>`;
    dropdown.style.display = "block";
    return;
  }
  dropdown.innerHTML = matches.map((name, idx) =>
    `<div onmousedown="event.preventDefault(); sfSelectSuburb('${name.replace(/'/g, "\\'")}')"
          style="padding:7px 12px;cursor:pointer;font-size:12px;color:var(--text);border-bottom:1px solid var(--border)${idx===matches.length-1?';border-bottom:none':''}"
          onmouseover="this.style.background='var(--panel2)';this.style.color='#FFC444'"
          onmouseout="this.style.background='transparent';this.style.color='var(--text)'">
      ${_sfTitleCase(name)}
    </div>`
  ).join("");
  dropdown.style.display = "block";
}

function sfSelectSuburb(name){
  const input = document.getElementById("sf-search");
  if(input) input.value = _sfTitleCase(name);
  sfHideDropdown();
  const sf = computeSnowflake(name);
  const h = document.getElementById("sf-headline");
  const c = document.getElementById("sf-chart");
  const r = document.getElementById("sf-scores");
  if(h) h.innerHTML = _sfHeadlineHTML(sf);
  if(c) c.innerHTML = renderSnowflakeSVG(sf);
  if(r) r.innerHTML = _sfRowsHTML(sf);
}

function sfHideDropdown(){
  const d = document.getElementById("sf-dropdown");
  if(d) d.style.display = "none";
}

function sfHandleKey(event){
  if(event.key === "Enter"){
    event.preventDefault();
    const dropdown = document.getElementById("sf-dropdown");
    if(dropdown && dropdown.firstElementChild && dropdown.firstElementChild.onmousedown){
      // Click first item
      dropdown.firstElementChild.dispatchEvent(new MouseEvent("mousedown"));
    }
  } else if(event.key === "Escape"){
    sfHideDropdown();
    event.target.blur();
  }
}

// ── SUBURB REPORT ─────────────────────────────────────────────────────────────

function _infraLabel(composite) {
  if (composite >= 3.5) return { text: 'Strong',   color: '#10D97A' };
  if (composite >= 2.5) return { text: 'Moderate', color: '#FFC444' };
  return                       { text: 'Limited',  color: '#FF6B6B' };
}

function _probLabel(p) {
  const status = (p.status || '').toLowerCase();
  const prob   = p.prob || 50;
  if (status.includes('operational') || status.includes('under construction') || prob >= 75)
    return { text: 'Confirmed', color: '#10D97A' };
  if (prob >= 45)
    return { text: 'Likely',    color: '#FFC444' };
  return   { text: 'At risk',   color: '#FF4455' };
}

function _politicalLabel(politicalRisk) {
  const r = politicalRisk != null ? politicalRisk : 50;
  if (r >= 65) return { text: 'High',   color: '#FF4455' };
  if (r >= 35) return { text: 'Medium', color: '#FFC444' };
  return        { text: 'Low',    color: '#10D97A' };
}

function _renderRadar6(axes6) {
  const cx = 180, cy = 165, rMax = 110, levels = 5, n = 6;
  const polar = (r, i) => {
    const deg = -90 + i * 60;
    const rad = deg * Math.PI / 180;
    return [cx + r * Math.cos(rad), cy + r * Math.sin(rad)];
  };
  let bg = '';
  for (let lvl = 1; lvl <= levels; lvl++) {
    const r = (lvl / levels) * rMax;
    const pts = Array.from({length: n}, (_, i) => polar(r, i).map(v => v.toFixed(1)).join(',')).join(' ');
    bg += `<polygon points="${pts}" fill="none" stroke="#4a5a6e" stroke-width="0.5" opacity="${(0.18 + 0.06 * lvl).toFixed(2)}"/>`;
  }
  let spokes = '';
  for (let i = 0; i < n; i++) {
    const [x, y] = polar(rMax, i);
    spokes += `<line x1="${cx}" y1="${cy}" x2="${x.toFixed(1)}" y2="${y.toFixed(1)}" stroke="#4a5a6e" stroke-width="0.5" opacity="0.45"/>`;
  }
  const pts = axes6.map((a, i) => {
    const r = (Math.max(1, Math.min(5, a.score)) / levels) * rMax;
    return polar(r, i).map(v => v.toFixed(1)).join(',');
  }).join(' ');
  const poly = `<polygon points="${pts}" fill="#FFC444" fill-opacity="0.22" stroke="#FFC444" stroke-width="2" stroke-linejoin="round"/>`;
  let dotsLabels = '';
  axes6.forEach((a, i) => {
    const score = Math.max(1, Math.min(5, a.score));
    const r = (score / levels) * rMax;
    const [dx, dy] = polar(r, i);
    const col = a.color || '#FFC444';
    dotsLabels += `<circle cx="${dx.toFixed(1)}" cy="${dy.toFixed(1)}" r="4" fill="${col}" stroke="#1A2535" stroke-width="1.5"/>`;
    dotsLabels += `<text x="${dx.toFixed(1)}" y="${(dy - 7).toFixed(1)}" text-anchor="middle" fill="${col}" font-family="Inter,sans-serif" font-size="8" font-weight="700">${score}</text>`;
    const [lx, ly] = polar(rMax + 22, i);
    const deg = -90 + i * 60;
    const cos = Math.cos(deg * Math.PI / 180);
    const sin = Math.sin(deg * Math.PI / 180);
    const anchor = cos > 0.25 ? 'start' : cos < -0.25 ? 'end' : 'middle';
    const labelY = ly + (sin > 0.15 ? 11 : sin < -0.15 ? -1 : 4);
    dotsLabels += `<text x="${lx.toFixed(1)}" y="${labelY.toFixed(1)}" text-anchor="${anchor}" fill="#aab8c8" font-family="Inter,sans-serif" font-size="9" font-weight="700" letter-spacing="0.4">${a.label}</text>`;
  });
  return `<svg viewBox="0 0 360 330" width="100%" style="max-width:320px;display:block;margin:0 auto"><g>${bg}</g><g>${spokes}</g>${poly}<g>${dotsLabels}</g></svg>`;
}

function openSuburbReport(rawName) {
  const upper   = (rawName || '').toUpperCase();
  const display = _sfTitleCase(upper);

  const sf        = computeSnowflake(upper);
  const composite = (sf.political.score + sf.budget.score + sf.spend.score + sf.momentum.score + sf.diversity.score) / 5;
  const infra     = _infraLabel(composite);

  let lga = '';
  const c = _suburbCentroid(upper);
  if (c && typeof COUNCILS_GEOJSON !== 'undefined')
    lga = _findContainingElec([c[1], c[0]], COUNCILS_GEOJSON, ['councilName']) || '';

  let catchProjs = [];
  try { catchProjs = projectsAffectingSuburb(upper) || []; } catch(e) {}

  const nearbyExtra = [];
  if (c) {
    (P || []).forEach(p => {
      if (catchProjs.some(x => x.project.id === p.id)) return;
      if (p.lat && p.lon && _haversineKm(c[0], c[1], p.lat, p.lon) <= 5)
        nearbyExtra.push(p);
    });
    nearbyExtra.sort((a, b) => _haversineKm(c[0], c[1], a.lat, a.lon) - _haversineKm(c[0], c[1], b.lat, b.lon));
  }
  const allProjs = [
    ...catchProjs.map(x => ({ project: x.project, inCatchment: true  })),
    ...nearbyExtra.map(p  => ({ project: p,         inCatchment: false })),
  ];
  allProjs.sort((a, b) => (b.project.val || 0) - (a.project.val || 0));

  const projIds  = new Set(allProjs.map(x => x.project.id));
  const newsItems = (_newsCache && _newsCache.articles ? _newsCache.articles : (ARTICLES || []))
    .filter(a => (a.pids || []).some(id => projIds.has(id)))
    .slice(0, 3);

  const confirmedCount = allProjs.filter(x => _probLabel(x.project).text === 'Confirmed').length;
  const headline = allProjs.length === 0
    ? 'No confirmed infrastructure projects found in this suburb\'s catchment area.'
    : confirmedCount > 0
      ? `${confirmedCount} confirmed project${confirmedCount !== 1 ? 's' : ''} within catchment — ${infra.text.toLowerCase()} infrastructure outlook.`
      : `${allProjs.length} project${allProjs.length !== 1 ? 's' : ''} nearby — further confirmation required before uplift is likely.`;

  const radar6 = [
    { label: 'INFRA',     score: Math.round(composite), color: infra.color  },
    { label: 'POLITICAL', score: sf.political.score,    color: '#9B6DFF'    },
    { label: 'BUDGET',    score: sf.budget.score,       color: '#FFC444'    },
    { label: 'SPEND',     score: sf.spend.score,        color: '#536253'    },
    { label: 'MOMENTUM',  score: sf.momentum.score,     color: '#10D97A'    },
    { label: 'DIVERSITY', score: sf.diversity.score,    color: '#FF8B45'    },
  ];

  const axisRows = [
    { label: '🏗 Infrastructure Score', score: Math.round(composite), hint: 'Overall infrastructure exposure — composite of the 5 axes below.',               detail: `${confirmedCount} confirmed, ${allProjs.length} total nearby projects.` },
    { label: '🗳 Political Risk',        score: sf.political.score,    hint: 'Higher = lower political risk (safe seats, funded and committed projects).',      detail: sf.political.detail },
    { label: '💰 Budget Commitment',    score: sf.budget.score,       hint: 'How firmly funded and committed are nearby projects.',                             detail: sf.budget.detail   },
    { label: '💵 Spend Concentration',  score: sf.spend.score,        hint: 'Infrastructure dollars attributable to this suburb specifically.',                 detail: sf.spend.detail    },
    { label: '🚧 Pipeline Momentum',    score: sf.momentum.score,     hint: 'Active, near-term delivery progress — rewards under-construction projects.',       detail: sf.momentum.detail },
    { label: '🔀 Project Diversity',    score: sf.diversity.score,    hint: 'Mix of project types: transport, housing, energy, water, other.',                  detail: sf.diversity.detail },
  ];

  const projCards = allProjs.slice(0, 8).map(({ project: p, inCatchment }) => {
    const catInfo  = CAT[p.cat] || {};
    const probLbl  = _probLabel(p);
    const politLbl = _politicalLabel(p.politicalRisk);
    const valStr   = (p.val || 0) >= 1000 ? `$${((p.val||0)/1000).toFixed(1)}B` : `$${p.val||0}M`;
    const locStr   = inCatchment ? 'In catchment' : 'Within 5km';
    const riskReason = p.overrun
      ? `Cost overrun already recorded (+${p.overrunPct||'?'}%). ${p.analogue ? p.analogue.split('.')[0]+'.' : ''}`
      : (p.risk === 'High' || (p.budgetRisk||0) > 60)
        ? 'High budget or delivery risk — monitor closely for schedule changes.'
        : 'No major overruns recorded. Standard delivery and political risk apply.';
    return `<div style="background:var(--panel2);border:1px solid var(--border2);border-radius:5px;padding:10px 12px;margin-bottom:8px">
      <div style="display:flex;align-items:flex-start;gap:8px;margin-bottom:8px">
        <div style="flex:1;min-width:0">
          <div style="font-size:11px;font-weight:700;color:var(--text);margin-bottom:3px;line-height:1.35">${p.name}</div>
          <div style="display:flex;gap:4px;flex-wrap:wrap;align-items:center">
            <span style="font-size:8px;padding:2px 5px;border-radius:2px;background:${catInfo.color||'#888'}18;color:${catInfo.color||'#888'};border:1px solid ${catInfo.color||'#888'}30;font-weight:700">${catInfo.icon||''} ${(p.cat||'other').toUpperCase()}</span>
            <span style="font-size:9px;color:var(--dim)">${locStr}</span>
            <span style="font-size:9px;font-weight:700;color:${probLbl.color}">${probLbl.text}</span>
          </div>
        </div>
        <div style="text-align:right;flex-shrink:0">
          <div style="font-size:11px;font-weight:700;color:var(--text)">${valStr}</div>
          <div style="font-size:8.5px;color:var(--dim)">Total value</div>
        </div>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:5px">
        <div style="background:var(--panel);border-radius:3px;padding:5px 7px">
          <div style="color:var(--dim);font-size:7.5px;letter-spacing:.05em;text-transform:uppercase;margin-bottom:2px">Completion Prob</div>
          <div style="font-weight:700;font-size:10px;color:${probLbl.color}">${probLbl.text}</div>
        </div>
        <div style="background:var(--panel);border-radius:3px;padding:5px 7px">
          <div style="color:var(--dim);font-size:7.5px;letter-spacing:.05em;text-transform:uppercase;margin-bottom:2px">Political Risk</div>
          <div style="font-weight:700;font-size:10px;color:${politLbl.color}">${politLbl.text}</div>
        </div>
        <div style="background:var(--panel);border-radius:3px;padding:5px 7px">
          <div style="color:var(--dim);font-size:7.5px;letter-spacing:.05em;text-transform:uppercase;margin-bottom:2px">Est. Completion</div>
          <div style="font-weight:700;font-size:10px;color:var(--text)">${p.year||'—'}</div>
        </div>
      </div>
      <div style="margin-top:5px;background:var(--panel);border-radius:3px;padding:5px 7px">
        <div style="color:var(--dim);font-size:7.5px;letter-spacing:.05em;text-transform:uppercase;margin-bottom:2px">Key Risk Factor</div>
        <div style="color:var(--muted);font-size:10px;line-height:1.4">${riskReason}</div>
      </div>
    </div>`;
  }).join('');

  const newsHtml = newsItems.length === 0
    ? `<div style="font-size:10px;color:var(--dim);padding:10px 12px;text-align:center">No recent news linked to nearby projects.</div>`
    : newsItems.map(a => {
        const d = a.date instanceof Date ? a.date : new Date(a.date);
        const dateStr = isNaN(d.getTime()) ? '' : d.toLocaleDateString('en-AU', {day:'numeric', month:'short'});
        return `<a href="${a.url}" target="_blank" rel="noopener" style="display:block;padding:9px 12px;border-bottom:1px solid var(--border);text-decoration:none" onmouseover="this.style.background='var(--panel2)'" onmouseout="this.style.background='transparent'">
          <div style="font-size:10px;color:var(--text);margin-bottom:2px;line-height:1.4">${a.title}</div>
          <div style="font-size:9px;color:var(--dim)">${a.src}${dateStr ? ` · ${dateStr}` : ''}</div>
        </a>`;
      }).join('');

  const html = `
    <div style="padding:14px 18px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center;background:var(--panel);flex-shrink:0">
      <div>
        <div style="font-size:16px;font-weight:700;color:var(--text)">${display}</div>
        <div style="font-size:11px;color:var(--dim);margin-top:2px">${lga || 'Sydney Metropolitan'} · Suburb Report</div>
      </div>
      <div style="display:flex;align-items:center;gap:12px">
        <div style="text-align:right">
          <div style="font-size:14px;font-weight:700;color:${infra.color};letter-spacing:.5px">${infra.text}</div>
          <div style="font-size:8.5px;color:var(--dim);letter-spacing:.08em;text-transform:uppercase">Infra Outlook</div>
        </div>
        <button onclick="closeModal()" style="background:none;border:1px solid var(--border2);color:var(--dim);padding:4px 10px;cursor:pointer;border-radius:3px;font-size:12px">✕</button>
      </div>
    </div>
    <div style="padding:10px 18px;background:var(--panel2);border-bottom:1px solid var(--border)">
      <div style="font-size:11px;color:var(--muted);line-height:1.5">${headline}</div>
    </div>
    <div style="padding:14px 18px;max-height:72vh;overflow-y:auto">
      <div style="margin-bottom:18px">
        <div style="font-size:9px;font-weight:700;color:var(--dim);letter-spacing:.1em;text-transform:uppercase;margin-bottom:10px">Suburb Profile</div>
        ${_renderRadar6(radar6)}
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-top:12px">
          ${axisRows.map(a => `<div style="background:var(--panel2);border-radius:4px;padding:8px 10px;border:1px solid var(--border2)">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:3px">
              <div style="font-size:10px;font-weight:700;color:var(--text)">${a.label}</div>
              <div style="font-size:11px;font-weight:700;color:#FFC444;font-family:var(--mono)">${a.score}<span style="color:var(--dim);font-weight:400;font-size:9px">/5</span></div>
            </div>
            <div style="font-size:9px;color:var(--dim);line-height:1.3;margin-bottom:3px">${a.hint}</div>
            <div style="font-size:9px;color:var(--muted);line-height:1.3;border-top:1px solid var(--border);padding-top:3px">${a.detail}</div>
          </div>`).join('')}
        </div>
      </div>
      <div style="margin-bottom:18px">
        <div style="font-size:9px;font-weight:700;color:var(--dim);letter-spacing:.1em;text-transform:uppercase;margin-bottom:10px">Projects Affecting This Suburb</div>
        ${allProjs.length === 0
          ? `<div style="font-size:10px;color:var(--dim);padding:14px;background:var(--panel2);border-radius:5px;text-align:center;border:1px solid var(--border2)">No projects found in catchment or within 5km radius.</div>`
          : projCards}
      </div>
      <div style="margin-bottom:18px;padding:11px 14px;background:var(--panel2);border-radius:5px;border:1px solid var(--border2);border-left:3px solid var(--blue)">
        <div style="font-size:10px;font-weight:700;color:var(--text);margin-bottom:5px">📈 Infrastructure-Driven Uplift Estimate</div>
        <div style="font-size:10px;color:var(--muted);line-height:1.6">Infrastructure-driven uplift estimate for <strong>${display}</strong>: see the 📈 Price Projection tool in the map toolbar for projected uplift ranges based on comparable Sydney project outcomes. Estimates are presented as ranges, not point estimates, with key assumptions listed.</div>
      </div>
      <div style="margin-bottom:18px">
        <div style="font-size:9px;font-weight:700;color:var(--dim);letter-spacing:.1em;text-transform:uppercase;margin-bottom:10px">Recent News</div>
        <div style="background:var(--panel2);border-radius:5px;border:1px solid var(--border2);overflow:hidden">${newsHtml}</div>
      </div>
      <div style="padding:10px 12px;background:#FF445508;border:1px solid #FF445520;border-radius:5px;font-size:9px;color:var(--dim);line-height:1.55">
        <strong style="color:var(--muted)">Financial Disclaimer:</strong> This report is not financial advice and not a recommendation to buy or sell property. All data is indicative only. Infrastructure project timelines, probabilities, and uplift estimates are modelled projections — not guaranteed outcomes. Users should seek independent financial and property advice before making investment decisions. Suburb data sourced from Cotality/Domain (Sep 2025). Infrastructure data from publicly available project registers.
      </div>
    </div>`;

  openModal(html);
}

function setPriceMode(mode, btn){
  ST.priceMode = mode;
  document.getElementById("pmode-growth")?.classList.remove("on");
  document.getElementById("pmode-projected")?.classList.remove("on");
  btn.classList.add("on");
  if(ST.showPrices){
    renderPriceLayer();
    const titleEl = document.getElementById("price-legend-title");
    const subEl = document.getElementById("price-legend-sub");
    if(titleEl && subEl){
      if(mode === "projected"){
        titleEl.textContent = `PROJECTED UPLIFT BY ${ST.maxYear}`;
        subEl.textContent = "Organic + infrastructure-driven · cumulative %";
      } else {
        titleEl.textContent = "PROPERTY PRICE GROWTH";
        subEl.textContent = "12-month change · Cotality / Domain Sep 2025";
      }
    }
  }
}

function renderMarkers(){
  Object.values(leafletMarkers).forEach(m => map.removeLayer(m));
  leafletMarkers = {};

  // ── 3. ACTIVE PROJECT LAYERS ──
  filtered().forEach(p => {
    const col = markerColor(p);
    const isSel = ST.selId === p.id;
    const popup = buildPopup(p);
    const crd = CORRIDORS[p.id];

    if(crd && crd.line && crd.line.length > 1){
      const lw = (crd.weight||3) + (isSel ? 2 : 0);
      const lo = isSel ? 1 : 0.80;

      // Cost overrun glow (solid, NOT dashed) — respects layer toggle
      if(p.overrun && isLayerOn("l-overrun")){
        const glow = L.polyline(crd.line, {
          color:"#FF4455", weight:lw+7, opacity:0.18, dashArray:null, lineCap:"round"
        }).addTo(map);
        leafletMarkers[`glow_${p.id}`] = glow;
      }

      // Main corridor
      const line = L.polyline(crd.line, {
        color:col, weight:lw, opacity:lo,
        dashArray:crd.dashArray||null, lineCap:"round", lineJoin:"round"
      }).addTo(map);
      line.bindPopup(popup, {maxWidth:340, autoPanPaddingTopLeft:[10,55]});
      line.on("click", ()=>{ ST.selId=p.id; updateMarkerIcons(); buildProjList(); });
      leafletMarkers[p.id] = line;

      // Station dots
      (crd.stations||[]).forEach(s => {
        const dot = L.circleMarker([s.lat,s.lon], {
          radius:isSel?6:4, fillColor:col,
          color:isSel?"#fff":"#06101A", weight:isSel?2:1.5,
          fillOpacity:isSel?1:0.92
        }).addTo(map);
        dot.bindTooltip(s.name, {className:"stn-tooltip", direction:"top", offset:[0,-5]});
        dot.bindPopup(popup, {maxWidth:340, autoPanPaddingTopLeft:[10,55]});
        dot.on("click", ()=>{ ST.selId=p.id; updateMarkerIcons(); buildProjList(); });
        leafletMarkers[`stn_${p.id}_${s.name.replace(/\W/g,"_")}`] = dot;
      });

      // Mid-corridor anchor
      const mid = crd.line[Math.floor(crd.line.length/2)];
      const anch = L.circleMarker(mid, {
        radius:isSel?9:6, fillColor:col, color:isSel?"#fff":col,
        weight:isSel?2.5:1.8, fillOpacity:isSel?1:0.92
      }).addTo(map);
      anch.bindPopup(popup, {maxWidth:340, autoPanPaddingTopLeft:[10,55]});
      anch.on("click", ()=>{ ST.selId=p.id; updateMarkerIcons(); buildProjList(); });
      leafletMarkers[`anchor_${p.id}`] = anch;

    } else {
      // POINT PROJECT (no corridor)
      const r = markerRadius(p.val);
      if(p.overrun && isLayerOn("l-overrun")){
        const glow = L.circleMarker([p.lat,p.lon], {
          radius:r+8, fillColor:"#FF4455", color:"transparent", weight:0, fillOpacity:0.16
        }).addTo(map);
        leafletMarkers[`glow_${p.id}`] = glow;
      }
      const m = L.circleMarker([p.lat,p.lon], {
        radius:r, fillColor:col,
        color:isSel?"#1a1a1a":"#FFFFFF", weight:isSel?2.5:2,
        fillOpacity:isSel?1:0.9, opacity:1
      }).addTo(map);
      m.bindPopup(popup, {maxWidth:340, autoPan:true});
      m.on("click", ()=>{ ST.selId=p.id; updateMarkerIcons(); buildProjList(); });
      leafletMarkers[p.id] = m;
    }
  });

  renderHeatmap();
  renderPriceLayer();
  renderTravelTimeLayer();
  renderAmenities();
  renderPoliticalLayers();
  updateStats();
  buildProjList();
  buildElecList();

  renderImpactZones();
}
function updateMarkerIcons(){
  filtered().forEach(p => {
    const col = markerColor(p);
    const isSel = ST.selId === p.id;
    const crd = CORRIDORS[p.id];
    if(crd && crd.line){
      // Update corridor line
      const line = leafletMarkers[p.id];
      if(line && line.setStyle){
        const lw = (crd.weight||3) + (isSel?2:0);
        line.setStyle({color:col,weight:lw,opacity:isSel?1:0.78,dashArray:crd.dashArray||null});
      }
      // Update anchor
      const anch = leafletMarkers[`anchor_${p.id}`];
      if(anch && anch.setStyle) anch.setStyle({fillColor:col,color:isSel?"#fff":col,weight:isSel?2:1,fillOpacity:isSel?0.95:0.6,radius:isSel?9:7});
      // Update station dots
      (crd.stations||[]).forEach(s => {
        const dot = leafletMarkers[`stn_${p.id}_${s.name.replace(/\s/g,"_")}`];
        if(dot && dot.setStyle) dot.setStyle({fillColor:col,color:isSel?"#fff":"#08121C",weight:isSel?2:1.5,fillOpacity:isSel?1:0.92,radius:isSel?6:4});
      });
    } else {
      const m = leafletMarkers[p.id];
      if(!m || !m.setStyle) return;
      const r = markerRadius(p.val);
      m.setStyle({fillColor:col,color:isSel?"#fff":col,weight:isSel?2.5:1,fillOpacity:isSel?0.9:0.5,radius:isSel?r+2:r});
    }
  });
}

