// POLICY IMPACT MATRIX
// How each major party's stated policy affects specific Sydney projects.
// Key for investors trying to model infra delivery risk under political change.
// ═══════════════════════════════════════════════════════════════

// ═══════════════════════════════════════════════════════════════
// ELECTORATE-LEVEL PARTY MARGIN COLOUR SCALE
// Matches Centre for Western Sydney style: 4-band intensity per party
// ═══════════════════════════════════════════════════════════════
function marginColour(party, margin){
  const m = Math.abs(margin);
  if(party === "ALP"){
    if(m < 5)  return "#FFB8C5";  // very marginal (light pink)
    if(m < 11) return "#E53E3E";  // marginal (red)
    if(m < 21) return "#A01020";  // safe (dark red)
    return "#5C0810";             // very safe (almost black red)
  }
  if(party === "LNP" || party === "LIB" || party === "NAT"){
    if(m < 5)  return "#BDD6F0";  // very marginal (light blue)
    if(m < 11) return "#3182CE";  // marginal (blue)
    if(m < 21) return "#1F4AA0";  // safe (dark blue)
    return "#0A2560";             // very safe (almost black blue)
  }
  if(party === "GRN") return "#2E7D32"; // Green
  if(party === "IND") return "#F9A825"; // Amber/yellow
  return "#6B4D8F"; // Other
}

function marginBandLabel(margin){
  const m = Math.abs(margin);
  if(m < 5)  return "Marginal (0-5%)";
  if(m < 11) return "Fairly safe (6-10%)";
  if(m < 21) return "Safe (11-20%)";
  return "Very safe (21%+)";
}


const ELEC_PARTY_COLOURS = {
  "ALP":"#E53E3E","LNP":"#3182CE","LIB":"#3182CE","NAT":"#3182CE",
  "IND":"#F9A825","GRN":"#38A169","Greens":"#38A169","Other":"#9B6DFF"
};

window._polLayers = [];

// Booth 2PP → colour gradient helper (used by showBooths)
function booth2ppColour(booth){
  const p = booth.vote.primary;
  if(p === "IND") return "#10D97A";
  if(p === "Greens") return "#38A169";
  const alp = booth.vote.ALP || 0;
  const lnp = booth.vote.LNP || 0;
  const margin = alp - lnp;
  if(margin > 15)  return "#A02030";
  if(margin > 8)   return "#D64052";
  if(margin > 3)   return "#E88090";
  if(margin > -3)  return "#9F6FB0";
  if(margin > -8)  return "#7090D0";
  if(margin > -15) return "#3B6BC0";
  return "#1F4AA0";
}

// Electorate tooltip HTML builder
function electorateTooltip(e, isState){
  const col = marginColour(e.party, e.margin);
  const band = marginBandLabel(e.margin);
  const swingCol = e.swing > 0 ? "#10D97A" : e.swing < 0 ? "#FF5FA0" : "#7A9AB8";
  const swingArr = e.swing > 0 ? "▲" : e.swing < 0 ? "▼" : "—";
  const noteHtml = e.note ? `<div style="margin-top:4px;font-size:8px;color:#FFB020;font-style:italic">⚠ ${e.note}</div>` : "";
  const projectCount = (e.pids||[]).length;
  return `<div style="font-family:var(--mono);font-size:10px;padding:6px 8px;min-width:230px;max-width:280px">
    <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px">
      <div>
        <div style="color:${col};font-weight:700;font-size:11px">${e.name}</div>
        <div style="color:#7A9AB8;font-size:8px;margin-top:1px">${isState?"NSW State":"Federal"} · ${e.incumbent||"—"}</div>
      </div>
      <div style="text-align:right">
        <div style="color:${col};font-weight:700;font-size:10px">${e.party}</div>
        <div style="color:#D4E4F4;font-size:9px">${e.margin.toFixed(1)}%</div>
      </div>
    </div>
    <div style="margin-top:5px;padding-top:4px;border-top:1px solid var(--border2);font-size:9px;color:#8AA8C0">
      ${band}${e.swing!==0?` · <span style="color:${swingCol}">${swingArr} ${Math.abs(e.swing).toFixed(1)}% swing</span>`:""}
    </div>
    ${projectCount > 0 ? `<div style="margin-top:3px;font-size:8px;color:#536253">🏗 ${projectCount} active infrastructure project${projectCount>1?"s":""}</div>` : ""}
    ${noteHtml}
  </div>`;
}

function renderPoliticalLayers(){
  window._polLayers.forEach(l => map.removeLayer(l));
  window._polLayers = [];

  // ─── BOOTH 2PP HEATMAP — uses real suburb polygons from SUBURBS_GEOJSON ───
  if(ST.showBooths){
    // Build a lookup from suburb name (lowercase, normalized) → GeoJSON feature
    const suburbLookup = {};
    (SUBURBS_GEOJSON?.features || []).forEach(f => {
      const name = (f.properties?.name || "").toLowerCase();
      if(name) suburbLookup[name] = f;
    });
    // Helper: get one or more candidate suburb names from a booth entry
    const candidateNames = (suburb) => {
      // Booth suburbs sometimes look like "Five Dock/Drummoyne" or "Parramatta CBD"
      // — split on slashes and strip common suffixes
      return suburb
        .split(/[\/&]/)
        .map(s => s.trim()
          .replace(/\s+CBD$/i, "")
          .replace(/\s+Valley$/i, "")
          .replace(/\s+\(.*\)$/, "")
        )
        .filter(Boolean);
    };

    (BOOTH_DATA||[]).forEach(b => {
      const col = booth2ppColour(b);
      const v = b.vote;
      const bars = ["ALP","LNP","Greens","IND"].filter(p => v[p]).map(party => {
        const partyCol = party==="ALP"?"#E53E3E":party==="LNP"?"#3182CE":party==="Greens"?"#38A169":"#F9A825";
        return `<div style="display:flex;align-items:center;gap:6px;margin:2px 0;font-size:9px">
          <span style="width:50px;color:${partyCol};font-weight:700">${party}</span>
          <div style="flex:1;height:5px;background:var(--panel2);border-radius:2px;overflow:hidden;min-width:80px">
            <div style="width:${Math.min(100,v[party])}%;height:100%;background:${partyCol}"></div>
          </div>
          <span style="width:36px;text-align:right;color:#D4E4F4;font-weight:700">${v[party].toFixed(1)}%</span>
        </div>`;
      }).join("");
      const tipHtml = `<div style="font-family:var(--mono);font-size:10px;padding:6px 8px;min-width:250px">
        <div style="display:flex;justify-content:space-between;margin-bottom:6px">
          <div><div style="color:${col};font-weight:700;font-size:11px">${b.suburb} <span style="color:var(--dim);font-weight:400">(${b.postcode})</span></div>
               <div style="color:#8AA8C0;font-size:8px">${b.electorate} · ${b.booth}</div></div>
          <div style="text-align:right"><div style="color:${col};font-weight:700">${v.primary} won</div></div>
        </div>
        <div style="padding-top:4px;border-top:1px solid var(--border2)">${bars}</div>
      </div>`;

      // Try to find real suburb polygon(s); fall back to rectangle if no match
      const names = candidateNames(b.suburb);
      const matchedFeatures = names
        .map(n => suburbLookup[n.toLowerCase()])
        .filter(Boolean);

      if(matchedFeatures.length > 0){
        // Render each matched suburb polygon
        matchedFeatures.forEach(f => {
          const layer = L.geoJSON(f, {
            style: () => ({
              color: col, fillColor: col,
              weight: 1.8, opacity: 0.95, fillOpacity: 0.55
            })
          }).addTo(map);
          layer.bindTooltip(tipHtml, {className:"stn-tooltip", sticky:true});
          window._polLayers.push(layer);
        });
      } else if(b.coords){
        // Fallback: original rectangle (only ~7 booths use this path)
        const poly = L.polygon(b.coords, {
          color: col, fillColor: col,
          weight: 1.5, opacity: 0.9, fillOpacity: 0.38, dashArray: "3,3"
        }).addTo(map);
        poly.bindTooltip(tipHtml + "<div style='font-size:8px;color:#FFB020;margin-top:4px'>⚠ Approximate boundary</div>", {className:"stn-tooltip", sticky:true});
        window._polLayers.push(poly);
      }
    });
  }

  // ─── STACK-AWARE POLITICAL POLYGONS ───
  // Each layer adapts its style based on what's underneath:
  //   bottom layer (whichever is lowest visible) gets full fill + colour
  //   layers above it get outline-only (no fill), thinner, with party-distinctive
  //   stroke styles so multiple layers can co-exist without colour pollution.
  //
  // Stack order (bottom→top): councils → state → federal → marginal
  const layersOn = {
    councils: ST.showCouncils && typeof COUNCILS_GEOJSON !== 'undefined',
    state:    ST.showState    && typeof STATE_BOUNDARIES_GEOJSON !== 'undefined',
    federal:  ST.showElec     && typeof FED_BOUNDARIES_GEOJSON !== 'undefined',
  };
  // Find the bottom-most visible layer — that one gets the fill, others outline-only
  const bottomLayer = layersOn.councils ? "councils"
                    : layersOn.state    ? "state"
                    : layersOn.federal  ? "federal"
                    : null;

  // ─── COUNCILS (z=300, dotted line — most permanent boundary) ───
  if(layersOn.councils){
    const partyColor = (party) => {
      if(party === "ALP") return "#E53E3E";
      if(party === "LIB" || party === "LNP") return "#3182CE";
      if(party === "GRN") return "#38A169";
      if(party === "IND") return "#F9A825";
      return "#9B6DFF";
    };
    const fillOn = bottomLayer === "councils";
    const layer = L.geoJSON(COUNCILS_GEOJSON, {
      pane: "councilsPane",
      style: feature => {
        const meta = COUNCIL_DATA[feature.properties.councilName];
        const col = meta ? partyColor(meta.party) : "#7A9AB8";
        return {
          color: col, weight: fillOn ? 1.8 : 1.4, opacity: fillOn ? 0.7 : 0.6,
          fillColor: col, fillOpacity: fillOn ? 0.12 : 0,
          dashArray: "1,4",  // dotted (visually distinct)
          lineCap: "round"
        };
      },
      onEachFeature: (feature, layer) => {
        const name = feature.properties.councilName;
        const meta = COUNCIL_DATA[name] || {};
        const col = meta.party ? partyColor(meta.party) : "#7A9AB8";
        const tip = `<div style="font-family:var(--mono);font-size:10px;padding:6px 8px;min-width:240px;max-width:300px">
          <div style="display:flex;justify-content:space-between;align-items:flex-start;gap:8px;margin-bottom:5px">
            <div>
              <div style="color:${col};font-weight:700;font-size:11px">🏛 ${name} Council</div>
              <div style="color:#7A9AB8;font-size:8px;margin-top:1px">${feature.properties.suburbCount||"?"} suburbs</div>
            </div>
            <div style="text-align:right">
              <div style="color:${col};font-weight:700;font-size:9px">${meta.party||"?"}</div>
            </div>
          </div>
          ${meta.mayor ? `<div style="font-size:9px;color:#D4E4F4;margin-bottom:5px;font-weight:600">Mayor: ${meta.mayor}</div>` : ""}
          ${meta.note ? `<div style="font-size:8px;color:#8AA8C0;line-height:1.45;padding:5px 7px;background:var(--panel);border-radius:3px;border-left:2px solid ${col}">${meta.note}</div>` : ""}
        </div>`;
        layer.bindTooltip(tip, {className:"stn-tooltip", sticky:true});
        // Hover: subtle highlight (don't change fill if no fill, just stroke)
        layer.on("mouseover", function(){
          this.setStyle({weight: 3, opacity: 1});
          this.bringToFront();
        });
        layer.on("mouseout", function(){
          this.setStyle({weight: fillOn ? 1.8 : 1.4, opacity: fillOn ? 0.7 : 0.6});
        });
      }
    }).addTo(map);
    window._polLayers.push(layer);
  }

  // ─── STATE ELECTORATES (z=350, short-dashed line) ───
  if(layersOn.state){
    const fillOn = bottomLayer === "state";
    const layer = L.geoJSON(STATE_BOUNDARIES_GEOJSON, {
      pane: "statePane",
      style: feature => {
        const n = (feature.properties.districtName||"").toLowerCase();
        const e = STATE_RESULTS_2023.find(x => x.name.toLowerCase() === n);
        if(!e) return {color:"#888", weight: fillOn ? 1 : 0.8, opacity:0.35, fillOpacity: fillOn ? 0.04 : 0, dashArray:"4,3"};
        const col = marginColour(e.party, e.margin);
        const fillOp = fillOn ? Math.min(0.32, 0.08 + Math.abs(e.margin) * 0.010) : 0;
        return {
          color: col, weight: fillOn ? 1.4 : 1.1, opacity: fillOn ? 0.75 : 0.7,
          fillColor: col, fillOpacity: fillOp,
          dashArray: "4,3", lineCap: "round"
        };
      },
      onEachFeature: (feature, layer) => {
        const n = (feature.properties.districtName||"").toLowerCase();
        const e = STATE_RESULTS_2023.find(x => x.name.toLowerCase() === n);
        const raw = feature.properties.districtName || "";
        const display = raw.split(" ").map(w => w[0] + w.slice(1).toLowerCase()).join(" ");
        if(e){
          layer.bindTooltip(electorateTooltip(e, true), {className:"stn-tooltip", sticky:true});
        } else if(display){
          layer.bindTooltip(`<div style="font-family:var(--mono);font-size:10px;padding:5px 8px"><b>${display}</b><br><small style="color:#8AA8C0">No 2023 result data</small></div>`,
            {className:"stn-tooltip", sticky:true});
        }
        layer.on("mouseover", function(){
          this.setStyle({weight: 2.5, opacity: 1});
          this.bringToFront();
        });
        layer.on("mouseout", function(){
          // restore original style by triggering re-style
          const n = (feature.properties.districtName||"").toLowerCase();
          const e = STATE_RESULTS_2023.find(x => x.name.toLowerCase() === n);
          const col = e ? marginColour(e.party, e.margin) : "#888";
          this.setStyle({weight: fillOn ? 1.4 : 1.1, opacity: fillOn ? 0.75 : 0.7, color: col});
        });
      }
    }).addTo(map);
    window._polLayers.push(layer);
  }

  // ─── FEDERAL ELECTORATES (z=400, solid line — most prominent) ───
  if(layersOn.federal){
    const fillOn = bottomLayer === "federal";
    const layer = L.geoJSON(FED_BOUNDARIES_GEOJSON, {
      pane: "federalPane",
      style: feature => {
        const n = (feature.properties.districtName||"").toLowerCase();
        const e = FED_RESULTS_2025.find(x => x.name.toLowerCase() === n);
        if(!e) return {color:"#888", weight: fillOn ? 1.2 : 1, opacity:0.45, fillOpacity: fillOn ? 0.05 : 0};
        const col = marginColour(e.party, e.margin);
        const fillOp = fillOn ? Math.min(0.38, 0.10 + Math.abs(e.margin) * 0.011) : 0;
        return {
          color: col, weight: fillOn ? 1.5 : 1.6, opacity: fillOn ? 0.85 : 0.85,
          fillColor: col, fillOpacity: fillOp,
          dashArray: null,  // solid (most prominent)
          lineCap: "round"
        };
      },
      onEachFeature: (feature, layer) => {
        const n = (feature.properties.districtName||"").toLowerCase();
        const e = FED_RESULTS_2025.find(x => x.name.toLowerCase() === n);
        const display = feature.properties.districtName || "Unknown";
        if(e){
          layer.bindTooltip(electorateTooltip(e, false), {className:"stn-tooltip", sticky:true});
        } else {
          layer.bindTooltip(`<div style="font-family:var(--mono);font-size:10px;padding:5px 8px"><b>${display}</b><br><small style="color:#8AA8C0">No 2025 result data</small></div>`,
            {className:"stn-tooltip", sticky:true});
        }
        layer.on("mouseover", function(){
          this.setStyle({weight: 3, opacity: 1});
          this.bringToFront();
        });
        layer.on("mouseout", function(){
          const n = (feature.properties.districtName||"").toLowerCase();
          const e = FED_RESULTS_2025.find(x => x.name.toLowerCase() === n);
          const col = e ? marginColour(e.party, e.margin) : "#888";
          this.setStyle({weight: fillOn ? 1.5 : 1.6, opacity: 0.85, color: col});
        });
      }
    }).addTo(map);
    window._polLayers.push(layer);
  }

  // ─── MARGINAL HIGHLIGHT OVERLAY ───
  // Highlights seats with <5% margin. Federal and state marginals each have their
  // own toggle (ST.marginal / ST.marginalState) and render in different colours
  // (purple #9B6DFF for federal, pink #FF5FA0 for state) so they can run together.
  if(ST.marginal || ST.marginalState){
    const showFedMarginals = ST.marginal;
    const showStateMarginals = ST.marginalState;

    // Use a labeled glow effect (filter brightness) rather than thick borders
    if(showFedMarginals && typeof FED_BOUNDARIES_GEOJSON !== 'undefined'){
      const fedMarginal = FED_RESULTS_2025.filter(e => Math.abs(e.margin) < 5);
      const fedNames = fedMarginal.map(e => e.name.toLowerCase());
      const fedLayer = L.geoJSON(FED_BOUNDARIES_GEOJSON, {
        filter: feature => fedNames.includes((feature.properties.districtName||"").toLowerCase()),
        pane: "marginalPane",
        style: () => ({
          color:"#9B6DFF", fillColor:"#9B6DFF",
          weight:3.5, opacity:1,
          fill: ST.showElec ? false : true,
          fillOpacity: 0.18,
          dashArray:null,
          lineCap:"round"
        }),
        interactive: true,
        onEachFeature: (feature, layer) => {
          const e = fedMarginal.find(x => x.name.toLowerCase() === (feature.properties.districtName||"").toLowerCase());
          if(e){
            layer.bindTooltip(`<div style="font-family:var(--mono);font-size:10px;padding:6px 8px;min-width:240px">
              <div style="display:flex;justify-content:space-between;margin-bottom:5px">
                <div style="color:#9B6DFF;font-weight:700;font-size:11px">⚠ ${e.name}</div>
                <div style="text-align:right">
                  <div style="font-size:9px;color:${marginColour(e.party,e.margin)};font-weight:700">${e.party} ${e.margin.toFixed(1)}%</div>
                </div>
              </div>
              <div style="font-size:8px;color:#7A9AB8;margin-bottom:4px">FEDERAL MARGINAL · ${e.incumbent || "—"}</div>
              <div style="font-size:8px;color:#FFB020;background:#3a2a14;padding:4px 6px;border-radius:3px;border-left:2px solid #9B6DFF;line-height:1.4">
                Margin under 5% means a small swing flips this seat. ${e.swing > 0 ? `▲${e.swing.toFixed(1)}% to ALP at last election` : e.swing < 0 ? `▼${Math.abs(e.swing).toFixed(1)}% to LNP at last election` : "No swing data"}.
              </div>
              ${e.note ? `<div style="font-size:8px;color:#FFB020;margin-top:4px;font-style:italic">${e.note}</div>` : ""}
            </div>`, {className:"stn-tooltip", sticky:true});
          }
        }
      }).addTo(map);
      window._polLayers.push(fedLayer);
    }

    if(showStateMarginals && typeof STATE_BOUNDARIES_GEOJSON !== 'undefined'){
      const stateMarginal = STATE_RESULTS_2023.filter(e => Math.abs(e.margin) < 5);
      const stateNames = stateMarginal.map(e => e.name.toLowerCase());
      const stateLayer = L.geoJSON(STATE_BOUNDARIES_GEOJSON, {
        filter: feature => stateNames.includes((feature.properties.districtName||"").toLowerCase()),
        pane: "marginalPane",
        style: () => ({
          color:"#FF5FA0", fillColor:"#FF5FA0",
          weight:3.5, opacity:1,
          fill:false,
          dashArray:null,
          lineCap:"round"
        }),
        interactive: true,
        onEachFeature: (feature, layer) => {
          const e = stateMarginal.find(x => x.name.toLowerCase() === (feature.properties.districtName||"").toLowerCase());
          if(e){
            layer.bindTooltip(`<div style="font-family:var(--mono);font-size:10px;padding:6px 8px;min-width:240px">
              <div style="display:flex;justify-content:space-between;margin-bottom:5px">
                <div style="color:#FF5FA0;font-weight:700;font-size:11px">⚠ ${e.name}</div>
                <div style="text-align:right">
                  <div style="font-size:9px;color:${marginColour(e.party,e.margin)};font-weight:700">${e.party} ${e.margin.toFixed(1)}%</div>
                </div>
              </div>
              <div style="font-size:8px;color:#7A9AB8;margin-bottom:4px">NSW STATE MARGINAL · ${e.incumbent || "—"}</div>
              <div style="font-size:8px;color:#FF5FA0;background:#3a1a28;padding:4px 6px;border-radius:3px;border-left:2px solid #FF5FA0;line-height:1.4">
                Margin under 5% means this is a swing seat at the 2027 NSW state election.
              </div>
              ${e.note ? `<div style="font-size:8px;color:#FFB020;margin-top:4px;font-style:italic">${e.note}</div>` : ""}
            </div>`, {className:"stn-tooltip", sticky:true});
          }
        }
      }).addTo(map);
      window._polLayers.push(stateLayer);
    }
  }
}
// ══════════════════════════════════════════════════════════════
// POPUP
// ══════════════════════════════════════════════════════════════
function buildPopup(p){
  const c = CAT[p.cat];
  const score = riskScore(p);
  const rc = score<=30?"#10D97A":score<=55?"#FFB020":score<=75?"#FF4455":"#CC0022";
  const risk = score<=30?"Low":score<=55?"Medium":score<=75?"High":"Very High";
  const pc = probColor(p.prob);
  const relNews = ARTICLES.filter(a => a.pids?.includes(p.id));

  const overrunTag = p.overrun ? `<span class="pu-badge" style="background:#FF445518;color:#FF4455;border:1px solid #FF445533">⚠ OVERRUN +${p.overrunPct}%</span>` : "";
  const newsHtml = relNews.slice(0,3).map(a => `<div class="pu-news-item" style="--pc:${c.color}">${relTime(a.date)} — ${a.title}</div>`).join("") || `<div style="font-size:9px;color:var(--dim)">No recent news</div>`;

  // ── FUNDING BREAKDOWN ──
  const f = p.funding || {state:0,private:0,local:0,other:0};
  const total = p.val || 1;
  const fedPct = Math.round((p.fed/total)*100);
  const statePct = Math.round((f.state/total)*100);
  const privatePct = Math.round((f.private/total)*100);
  const localPct = Math.round((f.local/total)*100);
  const otherPct = Math.max(0, 100 - fedPct - statePct - privatePct - localPct);

  const fundRow = (label, pct, amt, col) => pct > 0 ? `
    <div style="display:flex;justify-content:space-between;align-items:center;padding:2px 0;font-size:9px">
      <div style="display:flex;align-items:center;gap:6px">
        <span style="width:6px;height:6px;border-radius:50%;background:${col};display:inline-block"></span>
        <span style="color:#B8C8D8">${label}</span>
      </div>
      <div style="color:${col};font-weight:700;font-variant-numeric:tabular-nums">${fmtB(amt)} · ${pct}%</div>
    </div>` : "";

  const fundingHtml = `
    <div style="display:flex;height:10px;border-radius:3px;overflow:hidden;background:var(--panel2);margin-bottom:6px">
      ${fedPct>0?`<div style="width:${fedPct}%;background:#536253" title="Federal ${fedPct}%"></div>`:""}
      ${statePct>0?`<div style="width:${statePct}%;background:#FFB020" title="State ${statePct}%"></div>`:""}
      ${privatePct>0?`<div style="width:${privatePct}%;background:#FF5FA0" title="Private ${privatePct}%"></div>`:""}
      ${localPct>0?`<div style="width:${localPct}%;background:#10D97A" title="Local ${localPct}%"></div>`:""}
      ${otherPct>0?`<div style="width:${otherPct}%;background:#9B6DFF" title="Other ${otherPct}%"></div>`:""}
    </div>
    ${fundRow("Federal", fedPct, p.fed, "#536253")}
    ${fundRow("State (NSW)", statePct, f.state, "#FFB020")}
    ${fundRow("Private / PPP", privatePct, f.private, "#FF5FA0")}
    ${fundRow("Local Council", localPct, f.local, "#10D97A")}
    ${fundRow("Other", otherPct, f.other, "#9B6DFF")}
  `;

  return `<div style="--pc:${c.color}">
    <div class="pu-hdr">
      <div class="pu-cat" style="color:${c.color}">${c.icon} ${c.label.toUpperCase()} · ${p.sub}</div>
      <div class="pu-name">${p.name}</div>
      <div class="pu-sub">📍 ${p.electorate} · ${p.status}</div>
    </div>
    <div class="pu-desc">${p.desc}</div>
    <div class="pu-grid">
      <div><div class="pu-fl">Total Value</div><div class="pu-fv" style="color:${c.color}">${fmtB(p.val)}</div></div>
      <div><div class="pu-fl">Est. Delivery</div><div class="pu-fv">${p.year}</div></div>
      <div>
        <div class="pu-fl">Risk Score</div>
        <div class="pu-fv" style="color:${rc}">${risk} (${score})</div>
        <div class="pu-risk-bar"><div class="pu-risk-fill" style="width:${score}%;background:${rc}"></div></div>
      </div>
      <div>
        <div class="pu-fl">Prob. Proceed</div>
        <div class="pu-fv" style="color:${pc}">${p.prob}%</div>
        <div class="pu-risk-bar"><div class="pu-risk-fill" style="width:${p.prob}%;background:${pc}"></div></div>
      </div>
    </div>
    ${overrunTag ? `<div style="padding:6px 13px;border-bottom:1px solid var(--border)">${overrunTag}</div>` : ""}
    <div class="pu-section">
      <div class="pu-sl">💰 Funding Mix</div>
      ${fundingHtml}
    </div>
    ${(() => {
      const im = PROJECT_IMPACT[p.id];
      if(!im) return "";
      const cells = [];
      if(im.dwellings > 0) cells.push(`<div class="pu-impact-cell"><div class="pu-impact-num" style="color:#10D97A">${im.dwellings>=1000?(im.dwellings/1000).toFixed(0)+"k":im.dwellings}</div><div class="pu-impact-lbl">dwellings unlocked</div></div>`);
      if(im.population > 0) cells.push(`<div class="pu-impact-cell"><div class="pu-impact-num" style="color:#536253">${im.population>=1000?(im.population/1000).toFixed(0)+"k":im.population}</div><div class="pu-impact-lbl">population uplift</div></div>`);
      if(im.jobs > 0) cells.push(`<div class="pu-impact-cell"><div class="pu-impact-num" style="color:#FFB020">${im.jobs>=1000?(im.jobs/1000).toFixed(0)+"k":im.jobs}</div><div class="pu-impact-lbl">jobs (direct + indirect)</div></div>`);
      if(im.travelMins > 0) cells.push(`<div class="pu-impact-cell"><div class="pu-impact-num" style="color:#FF8B45">−${im.travelMins} min</div><div class="pu-impact-lbl">travel time saving</div></div>`);
      if(im.propertyUplift !== 0) cells.push(`<div class="pu-impact-cell"><div class="pu-impact-num" style="color:${im.propertyUplift>0?'#10D97A':'#FF4455'}">${im.propertyUplift>0?'+':''}${im.propertyUplift}%</div><div class="pu-impact-lbl">property value uplift</div></div>`);
      return `<div class="pu-section">
        <div class="pu-sl">📈 Quantified Impact</div>
        <div class="pu-impact-grid">${cells.join("")}</div>
        <div style="margin-top:6px;font-size:9px;color:var(--muted);line-height:1.5"><b style="color:#D4E4F4">${im.keyMetric||""}</b></div>
        ${im.tfnswForecast ? `<div style="font-size:10px;color:var(--dim);margin-top:3px">TfNSW: ${im.tfnswForecast}</div>` : ""}
        ${(im.catchmentSuburbs||[]).length ? `<div style="margin-top:5px;display:flex;flex-wrap:wrap;gap:3px">${im.catchmentSuburbs.slice(0,5).map(s => `<span style="font-size:8px;padding:2px 5px;background:${c.color}15;color:${c.color};border-radius:2px;border:1px solid ${c.color}33">${s}</span>`).join("")}</div>` : ""}
      </div>`;
    })()}
    <div class="pu-section">
      <div class="pu-sl">🏛 Governing Party</div>
      <div style="font-size:10px;color:var(--text);font-weight:600">${p.party}</div>
    </div>
    <div class="pu-section">
      <div class="pu-sl">📊 Electorate Context</div>
      <div style="font-size:9px;color:var(--muted)">
${(() => {
          const fed = FED_RESULTS_2025.filter(e => (e.pids||[]).includes(p.id));
          const state = STATE_RESULTS_2023.filter(e => (e.pids||[]).includes(p.id));
          const all = [...fed.map(e => ({...e, _level:"FED"})), ...state.map(e => ({...e, _level:"STATE"}))];
          if(!all.length) return '<span style="color:var(--dim)">No electorate mapping</span>';
          return all.map(e => {
            const col = marginColour(e.party, e.margin);
            return `<span class="pu-badge" style="background:${col}15;color:${col};border:1px solid ${col}55">${e._level}: ${e.name} (${e.party} ${e.margin.toFixed(1)}%)</span>`;
          }).join("");
        })()}
      </div>
    </div>
    <div class="pu-section">
      <div class="pu-sl">📚 Australian Track Record</div>
      <div style="font-size:9px;color:var(--muted);line-height:1.55">${p.analogue}</div>
    </div>
    <div class="pu-section" style="border:none">
      <div class="pu-sl">📡 Recent News</div>
      ${newsHtml}
    </div>
    <div class="pu-ai-area">
      <button class="pu-ai-btn" onclick="analyseProject(${p.id},this)">✦ AI Investment Analysis</button>
      <div class="pu-ai-result" id="pu-ai-${p.id}"></div>
    </div>
  </div>`;
}

async function analyseProject(id, btn){
  const p = P.find(x => x.id === id);
  if(!p) return;
  const box = document.getElementById(`pu-ai-${id}`);
  if(!box) return;
  if(box.classList.contains("show")){box.classList.remove("show");btn.textContent="✦ AI Investment Analysis";return;}
  btn.innerHTML = `<span class="ai-spinner"></span> Analysing…`;
  btn.disabled = true;
  const score = riskScore(p);
  const fedMatches = FED_RESULTS_2025.filter(e => (e.pids||[]).includes(p.id));
  const stateMatches = STATE_RESULTS_2023.filter(e => (e.pids||[]).includes(p.id));
  const elec = [...fedMatches.map(e => `Federal ${e.name} (${e.party} ${e.margin}% margin)`),
                ...stateMatches.map(e => `State ${e.name} (${e.party} ${e.margin}% margin)`)].join(", ") || "no electorate mapping";
  const prompt = `You are an Australian infrastructure investment analyst with expertise in housing investment near infrastructure projects. 
Project: ${p.name} (${p.cat}, $${p.val}M total, $${p.fed}M federal, ${p.status}, expected ${p.year})
Risk composite: ${score}/100 (${p.risk}). Probability to proceed: ${p.prob}%.
Analogue: ${p.analogue}
Electorates: ${elec}
Budget overrun: ${p.overrun ? `YES +${p.overrunPct}%` : "No"}.
In 3 concise sentences: (1) Investment opportunity for housing near this project, (2) Key risks to the project proceeding, (3) Recommended action for a property investor (buy now / wait / avoid).`;
  try{
    const r = await fetch("https://api.anthropic.com/v1/messages",{
      method:"POST",
      headers:{"Content-Type":"application/json"},
      body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:prompt}]})
    });
    const d = await r.json();
    box.textContent = d.content?.map(c=>c.text||"").join("") || "Unavailable.";
  }catch{box.textContent="Analysis unavailable.";}
  box.classList.add("show");
  btn.textContent="✦ Hide Analysis";
  btn.disabled=false;
}

