const LAYERS = [
  {id:"l-overrun", label:"Cost Overrun Glow", color:"#FF4455", on:true,
   desc:"Red glow around projects with >10% budget overrun"},
];

function buildLayerToggles(){
  document.getElementById("layer-toggles").innerHTML = LAYERS.map(l=>`
    <div class="ltoggle${l.on?" on":""}" id="${l.id}" style="--lc:${l.color}" onclick="toggleLayer('${l.id}',this)" title="${l.desc||l.label}">
      <div class="ltog-left${l.on?" on":""}" id="${l.id}-lbl"><span style="width:8px;height:8px;border-radius:50%;background:${l.color};display:inline-block;flex-shrink:0"></span>${l.label}</div>
      <div class="lswitch${l.on?" on":""}" id="${l.id}-sw"></div>
    </div>`).join("");
}

function toggleLayer(id, el){
  const l = LAYERS.find(x=>x.id===id);
  if(!l) return;
  l.on = !l.on;
  el.classList.toggle("on", l.on);
  document.getElementById(`${id}-sw`).classList.toggle("on", l.on);
  document.getElementById(`${id}-lbl`).classList.toggle("on", l.on);
  renderMarkers();
}

function isLayerOn(id){ const l=LAYERS.find(x=>x.id===id); return l ? l.on : false; }

function buildCatBtns(){
  document.getElementById("cat-btns").innerHTML = Object.entries(CAT).map(([k,v])=>`
    <button class="sb on" id="cat-${k}" style="--ac:${v.color}" onclick="toggleCat('${k}',this)">
      <div class="chk on" id="cchk-${k}" style="--ac:${v.color}"></div>${v.icon} ${v.label}
    </button>`).join("");
}

function toggleCat(k, btn){
  if(ST.cats.has(k)){ST.cats.delete(k);btn.classList.remove("on");document.getElementById(`cchk-${k}`).classList.remove("on");}
  else{ST.cats.add(k);btn.classList.add("on");document.getElementById(`cchk-${k}`).classList.add("on");}
  renderMarkers();
}

function buildProjList(){
  const vis = filtered().sort((a,b)=>{
    if(projSortMode==="val") return b.val-a.val;
    if(projSortMode==="prob") return b.prob-a.prob;
    if(projSortMode==="risk") return riskScore(b)-riskScore(a);
    return 0;
  });
  document.getElementById("pcount").textContent = vis.length;
  document.getElementById("proj-list").innerHTML = vis.map(p=>{
    const c = CAT[p.cat];
    const isSel = ST.selId === p.id;
    const score = riskScore(p);
    const pc = probColor(p.prob);
    return `<div class="pi${isSel?" on":""}" style="border-left-color:${isSel?c.color:"transparent"}" onclick="selFromList(${p.id})">
      <span style="font-size:12px">${c.icon}</span>
      <div style="flex:1;min-width:0">
        <div class="pi-name" style="color:${isSel?c.color:"var(--text)"}">${p.name}</div>
        <div class="pi-meta">${p.electorate.split("/")[0].trim()} · ${fmtB(p.val)} · ${p.status}</div>
      </div>
      <div style="display:flex;flex-direction:column;align-items:flex-end;gap:2px">
        <span style="font-size:8px;font-weight:700;color:${pc}">${p.prob}%</span>
        <div style="width:7px;height:7px;border-radius:50%;background:${RCOL[p.risk]}"></div>
      </div>
    </div>`;
  }).join("");
}

let elecListFilter = "all";  // "all" | "fed" | "state" | "marginal"

function setElecFilter(f, btn){
  elecListFilter = f;
  document.querySelectorAll(".elec-filter-pill").forEach(b => b.classList.remove("on"));
  btn.classList.add("on");
  buildElecList();
}

function buildElecList(){
  const list = document.getElementById("elec-list");
  if(!list) return;

  // Combine federal + state, apply filter, sort by margin
  let combined = [];
  if(elecListFilter === "all" || elecListFilter === "fed" || elecListFilter === "marginal"){
    combined = combined.concat(FED_RESULTS_2025.map(e => ({...e, _isState:false})));
  }
  if(elecListFilter === "all" || elecListFilter === "state" || elecListFilter === "marginal"){
    combined = combined.concat(STATE_RESULTS_2023.map(e => ({...e, _isState:true})));
  }
  if(elecListFilter === "marginal"){
    combined = combined.filter(e => Math.abs(e.margin) < 5);
  }
  combined.sort((a,b) => Math.abs(a.margin) - Math.abs(b.margin));

  // Filter header (renders once above the list)
  let html = `<div style="padding:7px 10px;border-bottom:1px solid var(--border);background:var(--panel);flex-shrink:0">
    <div style="display:flex;gap:3px;flex-wrap:wrap">
      <button class="mpill elec-filter-pill ${elecListFilter==='all'?'on':''}" onclick="setElecFilter('all',this)">All (${FED_RESULTS_2025.length + STATE_RESULTS_2023.length})</button>
      <button class="mpill elec-filter-pill ${elecListFilter==='fed'?'on':''}" onclick="setElecFilter('fed',this)">Federal (${FED_RESULTS_2025.length})</button>
      <button class="mpill elec-filter-pill ${elecListFilter==='state'?'on':''}" onclick="setElecFilter('state',this)">State (${STATE_RESULTS_2023.length})</button>
      <button class="mpill elec-filter-pill ${elecListFilter==='marginal'?'on':''}" onclick="setElecFilter('marginal',this)">Marginal &lt;5%</button>
    </div>
  </div>`;

  combined.forEach(e => {
    const col = marginColour(e.party, e.margin);
    const band = marginBandLabel(e.margin);
    const absSwing = Math.abs(e.swing || 0);
    const swingDir = (e.swing||0) > 0 ? "▲" : (e.swing||0) < 0 ? "▼" : "—";
    const swingCol = (e.swing||0) > 0 ? "#10D97A" : (e.swing||0) < 0 ? "#FF5FA0" : "#7A9AB8";
    const isMarginal = Math.abs(e.margin) < 5;
    const relProj = (e.pids||[]).map(id => {
      const p = P.find(x => x.id === id);
      return p ? `<span style="font-size:7px;color:${CAT[p.cat]?.color};background:${CAT[p.cat]?.color}15;padding:1px 4px;border-radius:2px;margin-right:2px">${CAT[p.cat]?.icon} ${p.name.split(" ").slice(0,3).join(" ")}</span>` : "";
    }).filter(Boolean).join("");

    html += `<div class="elec-row" onclick="selElectorateByName('${e.name.replace(/'/g,"\'")}',${e._isState})" style="border-left:3px solid ${col}">
      <div style="flex:1;min-width:0">
        <div style="display:flex;align-items:center;gap:5px;margin-bottom:3px;flex-wrap:wrap">
          <span style="font-weight:700;font-size:10px;color:${col}">${e.name}</span>
          <span style="font-size:7px;padding:1px 4px;border-radius:2px;background:${e._isState?'#3182CE18':'#E53E3E18'};color:${e._isState?'#3182CE':'#E53E3E'};border:1px solid ${e._isState?'#3182CE44':'#E53E3E44'}">${e._isState?'STATE':'FED'}</span>
          ${isMarginal?`<span style="font-size:7px;padding:1px 4px;border-radius:2px;background:#9B6DFF18;color:#9B6DFF;border:1px solid #9B6DFF44">MARGINAL</span>`:""}
          ${e.note ? `<span style="font-size:7px;padding:1px 4px;border-radius:2px;background:#FFB02015;color:#FFB020">⚠ ${e.note.split(" ").slice(0,3).join(" ")}</span>` : ""}
        </div>
        <div style="font-size:9px;color:var(--text);margin-bottom:2px">
          <span style="font-weight:700;color:${col}">${e.party}</span>
          <span style="color:var(--muted)"> ${e.margin.toFixed(1)}%</span>
          <span style="color:var(--dim);margin:0 4px">·</span>
          <span style="color:${swingCol}">${swingDir} ${absSwing.toFixed(1)}%</span>
          <span style="color:var(--dim);margin:0 4px">·</span>
          <span style="color:var(--dim);font-size:8px">${band}</span>
        </div>
        <div style="font-size:10px;color:var(--muted);margin-bottom:4px">${e.incumbent || "—"}</div>
        ${relProj ? `<div style="display:flex;flex-wrap:wrap;gap:2px">${relProj}</div>` : ""}
        <div class="swing-bar" style="margin-top:4px;background:var(--panel2);height:3px;border-radius:2px;overflow:hidden">
          <div style="height:100%;width:${Math.min(100, Math.abs(e.margin)*4)}%;background:${col};border-radius:2px"></div>
        </div>
      </div>
    </div>`;
  });

  list.innerHTML = html;
}

// Select electorate from list — focus map on it
function selElectorateByName(name, isState){
  const bounds = isState ? STATE_BOUNDARIES[name] : FED_BOUNDARIES[name];
  if(!bounds) return;
  // Enable the relevant layer if not on
  if(isState && !ST.showState){
    ST.showState = true;
    document.getElementById("btn-st")?.classList.add("on");
    document.getElementById("chk-st")?.classList.add("on");
    const leg = document.getElementById("elec-legend");
    if(leg) leg.style.display = "block";
  }
  if(!isState && !ST.showElec){
    ST.showElec = true;
    document.getElementById("btn-el")?.classList.add("on");
    document.getElementById("chk-el")?.classList.add("on");
    const leg = document.getElementById("elec-legend");
    if(leg) leg.style.display = "block";
  }
  renderMarkers();
  // Fly to centroid
  const lats = bounds.map(p => p[0]);
  const lngs = bounds.map(p => p[1]);
  const cLat = (Math.min(...lats) + Math.max(...lats)) / 2;
  const cLng = (Math.min(...lngs) + Math.max(...lngs)) / 2;
  map.flyTo([cLat, cLng], 12, {duration: 1.0});
}

function buildInvestPanel(){
  const panel = document.getElementById("invest-panel");
  let html = `<div style="padding:9px 10px;border-bottom:1px solid var(--border);background:var(--panel)">
    <div style="font-size:11px;font-weight:700;color:var(--text);margin-bottom:2px">🏡 Sydney Investment Hotspots</div>
    <div style="font-size:10px;color:var(--muted);line-height:1.5">Infrastructure-led investment opportunities, ranked by proximity to high-probability projects. Click to fly to location.</div>
  </div>`;
  HOTSPOTS.sort((a,b)=>b.score-a.score).forEach((h,i)=>{
    const scoreCol = h.score>=85?"#10D97A":h.score>=70?"#FFB020":"#536253";
    const relProj = h.pids.map(id=>{const p=P.find(x=>x.id===id);return p?`<span style="font-size:7px;color:${CAT[p.cat]?.color};background:${CAT[p.cat]?.color}12;border:1px solid ${CAT[p.cat]?.color}25;padding:1px 4px;border-radius:2px;margin:1px">${CAT[p.cat]?.icon} ${p.name.split(" ").slice(0,3).join(" ")}</span>`:""}).filter(Boolean).join("");
    html += `<div class="hs-card" style="--hs-col:${scoreCol}" onclick="flyToSpot('${h.id}')">
      <div style="background:${scoreCol}10;padding:8px 10px 6px;border-bottom:1px solid ${scoreCol}20">
        <div style="display:flex;align-items:center;gap:6px">
          <div class="hs-rank" style="background:${scoreCol}20;color:${scoreCol};border:1px solid ${scoreCol}44">${i+1}</div>
          <div style="flex:1;min-width:0"><div style="font-size:11px;font-weight:700;color:var(--text)">${h.name}</div><div style="font-size:10px;color:var(--dim)">${h.priceRange}</div></div>
          <div style="text-align:right"><div style="font-size:16px;font-weight:700;color:${scoreCol}">${h.score}</div><div style="font-size:9px;color:var(--dim)">SCORE</div></div>
        </div>
        <div class="hs-score-bar"><div class="hs-score-fill" style="width:${h.score}%;background:linear-gradient(to right,${scoreCol}88,${scoreCol})"></div></div>
      </div>
      <div style="padding:8px 10px;background:var(--panel2)">
        <div style="font-size:9px;color:var(--muted);line-height:1.5;margin-bottom:5px">${h.summary}</div>
        <div style="font-size:8px;color:#FF4455;background:#FF445510;border-left:2px solid #FF455540;padding:3px 6px;border-radius:2px;margin-bottom:5px">⚠ ${h.risks}</div>
        <div style="margin-bottom:5px">${relProj}</div>
        <div style="display:flex;gap:3px;flex-wrap:wrap">
          ${h.searchLinks.map(l=>`<a href="${l.url}" target="_blank" rel="noopener" style="font-size:7px;color:var(--blue);border:1px solid var(--blue)25;border-radius:2px;padding:1px 5px;text-decoration:none">${l.label} ↗</a>`).join("")}
        </div>
      </div>
    </div>`;
  });
  panel.innerHTML = html;
}

