// Filter map to only show projects affected by a specific policy
function filterByPolicy(policyIdx){
  const pi = POLICY_IMPACT[policyIdx];
  if(!pi || !pi.affects) return;
  // Highlight first affected project
  if(pi.affects.length > 0){
    selFromList(pi.affects[0]);
  }
}

