function switchTab(name, btn){
  ["news","proj","elec","invest","politics"].forEach(t => {
    const el = document.getElementById(`tab-${t}`);
    const b = document.getElementById(`tab-${t}-btn`);
    if(el){ el.style.display = t===name?"flex":"none"; el.style.flexDirection="column"; el.style.flex="1"; el.style.overflow="hidden"; }
    if(b){ b.style.color = t===name?"var(--blue)":"var(--dim)"; b.style.borderBottom = t===name?"2px solid var(--blue)":"2px solid transparent"; }
  });
  if(name==="invest") buildInvestPanel();
  if(name==="politics") buildPoliticsPanel();
}

const NTAG_CLASSES = "ntag-btn";
function setNewsTag(tag, btn){
  newsTagFilter = tag;
  document.querySelectorAll(".ntag-btn").forEach(b => b.classList.remove("on"));
  btn.classList.add("on");
  buildNews();
}

function filterNews(){
  newsSearchFilter = (document.getElementById("news-search")?.value||"").toLowerCase();
  buildNews();
}

function buildNews(){
  const list = document.getElementById("news-list");
  if(!list) return;
  const _allArts = (_newsCache?.articles?.length ? _newsCache.articles : ARTICLES) || [];
  // Update "last updated" indicator if present
  const updEl = document.getElementById("news-updated");
  if(updEl){
    const ts = _newsCache?._updated ? new Date(_newsCache._updated) : null;
    updEl.textContent = ts ? `updated ${relTime(ts)}` : `${_allArts.length} articles`;
  }
  let arts = _allArts.filter(a => {
    if(newsTagFilter && !a.cats.includes(newsTagFilter)) return false;
    if(newsSearchFilter && !a.title.toLowerCase().includes(newsSearchFilter)) return false;
    return true;
  });
  const today = new Date().toDateString();
  const yesterday = new Date(Date.now()-86400000).toDateString();
  let html = "", lastDay = null;
  arts.forEach(a => {
    const day = a.date.toDateString();
    if(day !== lastDay){
      const lbl = day===today?"TODAY":day===yesterday?"YESTERDAY":a.date.toLocaleDateString("en-AU",{weekday:"short",day:"numeric",month:"short"}).toUpperCase();
      html += `<div style="padding:3px 10px;font-size:9px;color:var(--dim);background:var(--panel);text-transform:uppercase;letter-spacing:.1em;border-bottom:1px solid var(--border);position:sticky;top:0;z-index:2">${lbl}</div>`;
      lastDay = day;
    }
    const sc = SCOL[a.sev]||"#555";
    const relProj = a.pids?.map(id=>{const p=P.find(x=>x.id===id);return p?`<span onclick="selFromList(${id})" style="cursor:pointer;font-size:7px;color:${CAT[p.cat]?.color};background:${CAT[p.cat]?.color}12;border:1px solid ${CAT[p.cat]?.color}25;padding:1px 4px;border-radius:2px;margin-right:2px">↗ ${p.name.split(" ").slice(0,3).join(" ")}</span>`:""}).filter(Boolean).join("")||"";
    html += `<div class="ni">
      <div style="display:flex;align-items:center;gap:4px;margin-bottom:3px">
        <span style="font-size:9px;color:var(--dim)">${relTime(a.date)}</span>
        <span style="font-size:7px;font-weight:700;padding:1px 4px;border-radius:2px;background:${sc}18;color:${sc};border:1px solid ${sc}33">${a.src}</span>
        <span style="font-size:7px;font-weight:700;padding:1px 4px;border-radius:2px;background:${sc}12;color:${sc}bb;margin-left:auto">${a.sev.toUpperCase()}</span>
      </div>
      <div style="padding-left:7px;border-left:2px solid ${sc}55">
        <a href="${a.url}" target="_blank" rel="noopener" class="ni-link">${a.title}</a>
        ${relProj?`<div style="margin-bottom:3px">${relProj}</div>`:""}
        <div style="display:flex;gap:3px;flex-wrap:wrap;align-items:center">
          ${a.cats.map(c=>`<span class="tag" style="background:${sc}12;color:${sc}88;border:1px solid ${sc}22">${c}</span>`).join("")}
          <button class="ai-btn" onclick="analyseNewsItem('${a.id}',this)">✦ AI</button>
          <a href="${a.url}" target="_blank" rel="noopener" style="font-size:7px;color:var(--blue);text-decoration:none;margin-left:auto;padding:1px 4px;border:1px solid var(--blue)25;border-radius:2px">open ↗</a>
        </div>
        <div class="ni-ai" id="ni-ai-${a.id}"></div>
      </div>
    </div>`;
  });
  if(!arts.length) html = `<div style="padding:20px;text-align:center;color:var(--dim);font-size:10px">No articles match.</div>`;
  list.innerHTML = html;
}

async function analyseNewsItem(id, btn){
  const _allArts = (_newsCache?.articles?.length ? _newsCache.articles : ARTICLES) || [];
  const a = _allArts.find(x=>x.id===id);
  if(!a) return;
  const box = document.getElementById(`ni-ai-${id}`);
  if(!box) return;
  if(box.classList.contains("show")){box.classList.remove("show");btn.textContent="✦ AI";return;}
  btn.innerHTML=`<span class="ai-spinner"></span>`;
  btn.disabled = true;
  const proj = a.pids?.map(id=>P.find(x=>x.id===id)?.name).filter(Boolean).join(", ");
  const prompt = `Sydney infrastructure analyst. 2 sentences: investment/property buyer implication of "${a.title}"${proj?`. Related projects: ${proj}`:""}.`;
  try{
    const r = await fetch("https://api.anthropic.com/v1/messages",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({model:"claude-sonnet-4-20250514",max_tokens:1000,messages:[{role:"user",content:prompt}]})});
    const d = await r.json();
    box.textContent = d.content?.map(c=>c.text||"").join("")||"Unavailable.";
  }catch{box.textContent="Analysis unavailable.";}
  box.classList.add("show");
  btn.textContent="✦ Hide";
  btn.disabled=false;
}

