// STATS
// ══════════════════════════════════════════════════════════════
function updateStats(){
  const vis = filtered();
  const tot = vis.reduce((a,p)=>a+p.val,0);
  const fed = vis.reduce((a,p)=>a+p.fed,0);
  const st = vis.reduce((a,p)=>a + (p.funding?.state||0),0);
  const pr = vis.reduce((a,p)=>a + (p.funding?.private||0),0);
  const hi = vis.filter(p=>p.risk==="High"||p.risk==="Very High").length;
  document.getElementById("h-total").textContent = fmtB(tot);
  document.getElementById("h-fed").textContent = fmtB(fed);
  const $st = document.getElementById("h-state"); if($st) $st.textContent = fmtB(st);
  const $pr = document.getElementById("h-private"); if($pr) $pr.textContent = fmtB(pr);
  document.getElementById("h-count").textContent = vis.length;
  document.getElementById("h-risk").textContent = hi;
}

