function setMode(m, btn){
  ST.mode = m;
  document.querySelectorAll(".hdr-mode-pill").forEach(b=>b.classList.remove("on"));
  btn.classList.add("on");
  updateMarkerIcons();
}

function toggleF(f, btnId, chkId){
  ST[f] = !ST[f];
  document.getElementById(btnId).classList.toggle("on", ST[f]);
  document.getElementById(chkId).classList.toggle("on", ST[f]);
  // Show/hide booth legend when booth toggle changes
  if(f === "showBooths"){
    const leg = document.getElementById("booth-legend");
    if(leg) leg.style.display = ST[f] ? "block" : "none";
  }
  if(f === "showElec" || f === "showState" || f === "showCouncils"){
    const el = document.getElementById("elec-legend");
    if(el) el.style.display = (ST.showElec || ST.showState || ST.showCouncils) ? "block" : "none";
  }
  if(f === "showTravelTime"){
    const el = document.getElementById("travel-legend");
    if(el) el.style.display = ST.showTravelTime ? "block" : "none";
  }
  if(f === "showPrices"){
    const el = document.getElementById("price-legend");
    if(el) el.style.display = ST.showPrices ? "block" : "none";
    // Update legend title based on mode
    const titleEl = document.getElementById("price-legend-title");
    const subEl = document.getElementById("price-legend-sub");
    if(titleEl && subEl){
      if(ST.priceMode === "projected"){
        titleEl.textContent = `PROJECTED UPLIFT BY ${ST.maxYear}`;
        subEl.textContent = "Organic + infrastructure-driven · cumulative %";
      } else {
        titleEl.textContent = "PROPERTY PRICE GROWTH";
        subEl.textContent = "12-month change · Cotality / Domain Sep 2025";
      }
    }
  }
  renderMarkers();
}

function setRange(r, btn){
  ST.range = r;
  document.querySelectorAll(".pill").forEach(b=>b.classList.remove("on"));
  btn.classList.add("on");
  renderMarkers();
}

function setProbFilter(f, btn){
  ST.probFilter = f;
  document.querySelectorAll(".pill").forEach(b=>{if(b.onclick&&b.onclick.toString().includes("setProbFilter")) b.classList.remove("on");});
  btn.classList.add("on");
  renderMarkers();
}

function setSort(s, btn){
  projSortMode = s;
  document.querySelectorAll(".mpill[id^='sort-']").forEach(b=>b.classList.remove("on"));
  btn.classList.add("on");
  buildProjList();
}

function selFromList(id){
  const p = P.find(x=>x.id===id);
  if(!p) return;
  // If compare mode is active, add to compare set instead of selecting
  const cmpBtn = document.getElementById("cmp-toggle-btn");
  if(cmpBtn?.classList.contains("active")){
    addToCompare(id);
    return;
  }
  ST.selId = id;
  updateMarkerIcons();
  buildProjList();
  const crd = CORRIDORS[id];
  let target;
  if(crd && crd.line && crd.line.length > 1){
    const mid = crd.line[Math.floor(crd.line.length/2)];
    target = mid;
  } else {
    target = [p.lat, p.lon];
  }
  map.flyTo(target, Math.max(map.getZoom(), 12), {duration: 1.2});
  setTimeout(()=>{
    const anch = leafletMarkers[`anchor_${id}`] || leafletMarkers[id];
    if(anch && anch.openPopup) anch.openPopup();
  }, 1300);
}

function selElectorate(id){
  // Legacy function — now uses selElectorateByName(name, isState) via buildElecList
  // Kept for backward compatibility only
  return;
}

function flyToSpot(id){
  const h = HOTSPOTS.find(x=>x.id===id);
  if(!h) return;
  map.flyTo([h.lat, h.lon], 13, {duration:1.5});
}

function toggleRiskLegend(){
  document.getElementById("risk-legend-tip").classList.toggle("show");
}

export async function _boot() {
  const _data = await _loadAll();
  P = _data.P;
  PROJECT_IMPACT = _data.PROJECT_IMPACT;
  ELECTORATES = _data.ELECTORATES;
  CBD_STATIONS = _data.CBD_STATIONS;
  BOOTH_DATA = _data.BOOTH_DATA;
  AMENITIES = _data.AMENITIES;
  SUBURB_PRICES = _data.SUBURB_PRICES;
  POLICY_IMPACT = _data.POLICY_IMPACT;
  ARTICLES = _data.ARTICLES;
  SUBURBS_GEOJSON = _data.SUBURBS_GEOJSON;
  FED_BOUNDARIES_GEOJSON = _data.FED_BOUNDARIES_GEOJSON;
  STATE_BOUNDARIES_GEOJSON = _data.STATE_BOUNDARIES_GEOJSON;
  COUNCILS_GEOJSON = _data.COUNCILS_GEOJSON;

  // ── Original boot sequence ──

  // ══════════════════════════════════════════════════════════════
  // BOOT
  // ══════════════════════════════════════════════════════════════
  buildCatBtns();
  buildLayerToggles();
  buildNews(); // render baked articles immediately
  refreshLiveNews(); // fetch live in background; calls buildNews() again when done


  initMap();
  updateStats();

  setInterval(()=>refreshLiveNews(), 300000); // refresh live news every 30 min

  // Expose module-scoped functions to window so HTML onclick= attributes resolve correctly.
  const _globals = {
    // From static HTML
    closeModal, exportCSV, exportPNG, filterNews, onSearch, onTimelineChange,
    openImpactRankings, openNewsFeed, openPresets, openPriceProjection,
    openSimulator, openSnowflakeModal, openSourcesModal, setMode, setNewsTag,
    setPriceMode, setProbFilter, setRange, setSort, switchTab, toggleAmenity,
    toggleCompareMode, toggleElecLegend, toggleF, toggleRiskLegend,
    // From dynamically-generated HTML
    analyseNewsItem, analyseProject, applyFilters, applySimulation,
    deletePreset, filterByPolicy, flyToSpot, saveCurrentPreset,
    selElectorateByName, selFromList, setElecFilter,
    sfFilterDropdown, sfHandleKey, sfSelectSuburb, sfHideDropdown,
    toggleCat, toggleLayer, updateComparePanel, refreshLiveNews,
    openSuburbReport,
  };
  Object.assign(window, _globals);
}
